export function toToolInputJsonSchema(schema: ZodTypeAny) {
  const { $schema, definitions, ...jsonSchema } = zodToJsonSchema(schema, {
    $refStrategy: "none",
    target: "jsonSchema7",
  });

  return jsonSchema;
}

