import { z } from "zod";

const telegramMcpEnvSchema = z.object({
  TELEGRAM_SESSION: z.string().min(1, "TELEGRAM_SESSION is required"),
  TELEGRAM_API_ID: z
    .string()
    .min(1, "TELEGRAM_API_ID is required")
    .regex(/^\d+$/, "TELEGRAM_API_ID must be a numeric string"),
  TELEGRAM_API_HASH: z.string().min(1, "TELEGRAM_API_HASH is required"),
});

export type TelegramMcpEnv = z.infer<typeof telegramMcpEnvSchema>;

export function parseTelegramMcpEnv(
  env: NodeJS.ProcessEnv | Record<string, string | undefined>
): TelegramMcpEnv {
  const parsed = telegramMcpEnvSchema.safeParse({
    TELEGRAM_SESSION: env.TELEGRAM_SESSION,
    TELEGRAM_API_ID: env.TELEGRAM_API_ID,
    TELEGRAM_API_HASH: env.TELEGRAM_API_HASH,
  });

  if (!parsed.success) {
    const first = parsed.error.flatten().fieldErrors;
    const msg = Object.entries(first)
      .map(([k, v]) => `${k}: ${v?.join(", ")}`)
      .join("; ");
    throw new Error(msg || parsed.error.message);
  }

  return parsed.data;
}
