const POLL_MS = 1500;
const MAX_TRANSCRIBE_POLLS = 15;

function delay(ms: number): Promise<void> {
  return new Promise((resolve) => {
    setTimeout(resolve, ms);
  });
}

function folderTitleText(title: unknown): string {
  if (typeof title === "string") {
    return title;
  }
  if (
    title &&
    typeof title === "object" &&
    "text" in title &&
    typeof (title as { text: string }).text === "string"
  ) {
    return (title as { text: string }).text;
  }
  return "";
}

function downloadsDir(): string {
  const dir = join(process.cwd(), "downloads");
  mkdirSync(dir, { recursive: true });
  return dir;
}

function telegramErrorMessage(error: unknown): string | undefined {
  if (
    typeof error === "object" &&
    error !== null &&
    "errorMessage" in error &&
    typeof (error as { errorMessage: string }).errorMessage === "string"
  ) {
    return (error as { errorMessage: string }).errorMessage;
  }
  return undefined;
}

function errorMessage(error: unknown): string {
  if (error instanceof Error) {
    return error.message;
  }

  const telegramMessage = telegramErrorMessage(error);
  if (telegramMessage) {
    return telegramMessage;
  }

  return String(error);
}

export async function gramJsSendPhoto(
  client: TelegramClient,
  input: {
    chatId: string;
    photoPath: string;
    caption?: string;
    replyToId?: number;
  }
): Promise<SendPhotoResult> {
  const sent = await client.sendFile(input.chatId, {
    file: input.photoPath,
    caption: input.caption,
    ...(input.replyToId !== undefined ? { replyTo: input.replyToId } : {}),
  });
  return { messageId: sent.id, date: sent.date };
}

export async function gramJsSendVoice(
  client: TelegramClient,
  input: {
    chatId: string;
    voicePath: string;
    caption?: string;
    replyToId?: number;
    duration?: number;
    waveform?: number[];
  }
): Promise<SendVoiceResult> {
  const sent = await client.sendFile(input.chatId, {
    file: input.voicePath,
    caption: input.caption,
    ...(input.replyToId !== undefined ? { replyTo: input.replyToId } : {}),
    attributes: [
      new Api.DocumentAttributeAudio({
        voice: true,
        duration: input.duration ?? 0,
        ...(input.waveform !== undefined
          ? { waveform: Buffer.from(input.waveform) }
          : {}),
      }),
    ],
  });
  return { messageId: sent.id, date: sent.date, message: "Voice message sent" };
}

export async function gramJsSendSticker(
  client: TelegramClient,
  input: {
    chatId: string;
    stickerSetShortName?: string;
    stickerIndex?: number;
    stickerPath?: string;
    replyToId?: number;
  }
): Promise<SendStickerResult> {
  if (
    input.stickerSetShortName !== undefined &&
    input.stickerIndex !== undefined
  ) {
    const shortName = input.stickerSetShortName;
    const stickerIndex = input.stickerIndex;
    const stickerSet = (await client.invoke(
      new Api.messages.GetStickerSet({
        stickerset: new Api.InputStickerSetShortName({
          shortName,
        }),
        hash: 0,
      })
    )) as Api.messages.StickerSet;

    const docs = stickerSet.documents ?? [];
    if (docs.length === 0) {
      throw new Error(`Sticker set '${shortName}' is empty or not found`);
    }
    if (stickerIndex >= docs.length) {
      throw new Error(
        `Sticker index ${String(stickerIndex)} out of range (0-${String(docs.length - 1)})`
      );
    }
    const stickerDoc = docs[stickerIndex] as Api.Document;
    await client.invoke(
      new Api.messages.SendMedia({
        peer: input.chatId,
        media: new Api.InputMediaDocument({
          id: new Api.InputDocument({
            id: stickerDoc.id,
            accessHash: stickerDoc.accessHash,
            fileReference: stickerDoc.fileReference,
          }),
        }),
        message: "",
        randomId: helpers.generateRandomBigInt(),
        replyTo:
          input.replyToId !== undefined
            ? new Api.InputReplyToMessage({
                replyToMsgId: input.replyToId,
              })
            : undefined,
      })
    );
    return {
      stickerSet: shortName,
      stickerIndex,
      totalInSet: docs.length,
    };
  }

  if (input.stickerPath !== undefined) {
    const stickerPath = input.stickerPath;
    const sent = await client.sendFile(input.chatId, {
      file: stickerPath,
      ...(input.replyToId !== undefined ? { replyTo: input.replyToId } : {}),
    });
    return { messageId: sent.id, date: sent.date };
  }

  throw new Error(
    "Must provide either (stickerSetShortName + stickerIndex) or stickerPath"
  );
}

export async function gramJsSendGif(
  client: TelegramClient,
  input: {
    chatId: string;
    queryId?: string;
    resultId?: string;
    gifPath?: string;
    caption?: string;
    replyToId?: number;
  }
): Promise<SendGifResult> {
  if (input.queryId !== undefined && input.resultId !== undefined) {
    const queryId = input.queryId;
    const resultId = input.resultId;
    await client.invoke(
      new Api.messages.SendInlineBotResult({
        peer: input.chatId,
        queryId: helpers.returnBigInt(queryId),
        id: resultId,
        randomId: helpers.generateRandomBigInt(),
        replyTo:
          input.replyToId !== undefined
            ? new Api.InputReplyToMessage({
                replyToMsgId: input.replyToId,
              })
            : undefined,
      })
    );
    return {
      sentVia: "inline_bot",
      queryId,
      resultId,
    };
  }

  if (input.gifPath !== undefined) {
    const gifPath = input.gifPath;
    const sent = await client.sendFile(input.chatId, {
      file: gifPath,
      caption: input.caption,
      ...(input.replyToId !== undefined ? { replyTo: input.replyToId } : {}),
      attributes: [new Api.DocumentAttributeAnimated()],
    });
    return { messageId: sent.id, date: sent.date };
  }

  throw new Error("Must provide either (queryId + resultId) or gifPath");
}

export async function gramJsDownloadMedia(
  client: TelegramClient,
  input: { chatId: string; messageId: number; filename?: string }
): Promise<DownloadMediaResult> {
  const messages = await client.getMessages(input.chatId, {
    ids: [input.messageId],
  });
  if (!messages.length) {
    throw new Error(
      `Message ${String(input.messageId)} not found in chat ${input.chatId}`
    );
  }
  const message = messages[0];
  if (!message.media) {
    throw new Error("Message does not contain any media");
  }

  let extension = "";
  let mediaType = "unknown";

  if (message.photo) {
    extension = ".jpg";
    mediaType = "photo";
  } else if (message.video) {
    extension = ".mp4";
    mediaType = "video";
  } else if (message.audio) {
    extension = ".mp3";
    mediaType = "audio";
  } else if (message.voice) {
    extension = ".ogg";
    mediaType = "voice";
  } else if (message.videoNote) {
    extension = ".mp4";
    mediaType = "video_note";
  } else if (message.sticker) {
    const stickerDoc = message.sticker;
    if (stickerDoc?.mimeType === "application/x-tgsticker") {
      extension = ".tgs";
    } else if (stickerDoc?.mimeType === "video/webm") {
      extension = ".webm";
    } else {
      extension = ".webp";
    }
    mediaType = "sticker";
  } else if (message.document) {
    const doc = message.document as Api.Document;
    let hasName = false;
    if (doc.attributes) {
      for (const attr of doc.attributes) {
        if (attr instanceof Api.DocumentAttributeFilename) {
          hasName = true;
          extension = "";
          break;
        }
      }
    }
    if (!hasName) {
      extension = ".bin";
    }
    mediaType = "document";
  } else if (message.gif) {
    extension = ".mp4";
    mediaType = "gif";
  }

  if (input.filename) {
    const providedExt = extname(input.filename).toLowerCase();
    const expectedExt = extension.toLowerCase();
    if (expectedExt && !providedExt) {
      throw new Error(
        `Missing extension: filename must have extension '${expectedExt}' for ${mediaType}`
      );
    }
    if (providedExt && !expectedExt) {
      throw new Error(
        `Unexpected extension: ${mediaType} does not use filename extension`
      );
    }
    if (providedExt && expectedExt && providedExt !== expectedExt) {
      throw new Error(
        `Extension mismatch: expected '${expectedExt}' for ${mediaType}`
      );
    }
  }

  const finalFilename =
    input.filename ??
    `${input.chatId}_${String(input.messageId)}_${String(Date.now())}${extension}`;
  const absolutePath = join(downloadsDir(), finalFilename);

  const buffer = await client.downloadMedia(message, {});
  if (!buffer) {
    throw new Error("Failed to download media - empty buffer returned");
  }
  const buf = Buffer.isBuffer(buffer) ? buffer : Buffer.from(buffer);
  writeFileSync(absolutePath, buf);

  return {
    filePath: join("downloads", finalFilename),
    absolutePath,
    mediaType,
    size: buf.length,
    filename: finalFilename,
  };
}

const SUPPORTED_IMAGE_MIMES = new Set([
  "image/jpeg",
  "image/png",
  "image/gif",
  "image/webp",
]);

const EXT_TO_MIME: Record<string, string> = {
  ".jpg": "image/jpeg",
  ".jpeg": "image/jpeg",
  ".png": "image/png",
  ".gif": "image/gif",
  ".webp": "image/webp",
};

const MAX_IMAGE_BYTES = 5 * 1024 * 1024;

async function openAiVisionDescribe(
  base64: string,
  mimeType: string,
  prompt: string
): Promise<{ text: string; usage?: Record<string, unknown> }> {
  const apiKey = process.env.OPENAI_API_KEY;
  if (!apiKey) {
    throw new Error(
      "Set OPENAI_API_KEY in the environment to use vision_analyze"
    );
  }
  const model = process.env.TELEGRAM_VISION_MODEL ?? "gpt-4o-mini";
  const res = await fetch("https://api.openai.com/v1/chat/completions", {
    method: "POST",
    headers: {
      Authorization: `Bearer ${apiKey}`,
      "Content-Type": "application/json",
    },
    body: JSON.stringify({
      model,
      max_tokens: 1024,
      messages: [
        {
          role: "user",
          content: [
            { type: "text", text: prompt },
            {
              type: "image_url",
              image_url: {
                url: `data:${mimeType};base64,${base64}`,
              },
            },
          ],
        },
      ],
    }),
  });
  if (!res.ok) {
    const errText = await res.text();
    throw new Error(`OpenAI vision request failed: ${res.status} ${errText}`);
  }
  const body = (await res.json()) as {
    choices?: Array<{ message?: { content?: string } }>;
    usage?: Record<string, unknown>;
  };
  const text = body.choices?.at(0)?.message?.content ?? "";
  if (!text) {
    throw new Error("Model did not return any analysis");
  }
  return { text, usage: body.usage };
}

export async function gramJsVisionAnalyze(
  client: TelegramClient,
  input: {
    chatId?: string;
    messageId?: number;
    filePath?: string;
    prompt?: string;
  }
): Promise<VisionAnalyzeResult> {
  const hasFile = Boolean(input.filePath);
  const hasTg =
    input.chatId !== undefined && input.messageId !== undefined;
  if (!hasFile && !hasTg) {
    throw new Error(
      "Provide filePath or both chatId and messageId for vision_analyze"
    );
  }

  const promptText = input.prompt ?? "Describe this image in detail.";
  let data: Buffer;
  let mimeType: string;
  let source: string;

  if (hasFile) {
    const abs = input.filePath?.startsWith("/")
      ? input.filePath
      : join(process.cwd(), input.filePath ?? "");
    const ext = extname(abs).toLowerCase();
    mimeType = EXT_TO_MIME[ext] ?? "application/octet-stream";
    if (!SUPPORTED_IMAGE_MIMES.has(mimeType)) {
      throw new Error(
        `Unsupported file type for vision: ${ext}. Use jpg, png, gif, or webp`
      );
    }
    data = readFileSync(abs);
    source = `file:${input.filePath ?? ""}`;
  } else {
    const messages = await client.getMessages(input.chatId ?? "", {
      ids: [input.messageId ?? 0],
    });
    const message = messages[0];
    if (!message?.media) {
      throw new Error("Message does not contain any media");
    }
    mimeType = "image/jpeg";
    if (message.photo) {
      mimeType = "image/jpeg";
    } else if (message.document) {
      const doc = message.document as Api.Document;
      mimeType = doc.mimeType ?? "application/octet-stream";
      if (!SUPPORTED_IMAGE_MIMES.has(mimeType)) {
        throw new Error(
          `Unsupported media type for vision: ${mimeType}`
        );
      }
    } else {
      throw new Error("Message does not contain a photo or image document");
    }
    const buffer = await client.downloadMedia(message, {});
    if (!buffer) {
      throw new Error("Failed to download image");
    }
    data = Buffer.isBuffer(buffer) ? buffer : Buffer.from(buffer);
    source = `telegram:${input.chatId}/${String(input.messageId)}`;
  }

  if (data.length > MAX_IMAGE_BYTES) {
    throw new Error("Image exceeds 5MB limit for vision_analyze");
  }

  const { text, usage } = await openAiVisionDescribe(
    data.toString("base64"),
    mimeType,
    promptText
  );

  return {
    analysis: text,
    source,
    imageSize: data.length,
    mimeType,
    usage,
  };
}

export type TranscribeInvokeResult = {
  pending?: boolean;
  text?: string;
  transcriptionId?: { toString(): string };
  trialRemainsNum?: number;
  trialRemainsUntilDate?: number;
};

export type TranscribePollState = {
  result: TranscribeInvokeResult;
  lastErrorMessage?: string;
  errorCount: number;
};

export async function transcribePollLoop(
  invoke: () => Promise<TranscribeInvokeResult>,
  state: TranscribePollState,
  remaining: number
): Promise<TranscribePollState> {
  if (!state.result.pending || remaining <= 0) {
    return state;
  }
  await delay(POLL_MS);
  try {
    const next = await invoke();
    return transcribePollLoop(
      invoke,
      {
        result: next,
        errorCount: state.errorCount,
      },
      remaining - 1
    );
  } catch (error) {
    const lastErrorMessage = errorMessage(error);
    if (remaining <= 1) {
      throw new Error(
        `Transcription polling failed after ${String(state.errorCount + 1)} polling errors: ${lastErrorMessage}`
      );
    }

    return transcribePollLoop(
      invoke,
      {
        result: state.result,
        lastErrorMessage,
        errorCount: state.errorCount + 1,
      },
      remaining - 1
    );
  }
}

export async function gramJsTranscribeAudio(
  client: TelegramClient,
  input: { chatId: string; messageId: number }
): Promise<TranscribeAudioResult> {
  const entity = await client.getEntity(input.chatId);

  const invoke = async () =>
    client.invoke(
      new Api.messages.TranscribeAudio({
        peer: entity,
        msgId: input.messageId,
      })
    ) as Promise<TranscribeInvokeResult>;

  try {
    const first = await invoke();
    const pollState = first.pending
      ? await transcribePollLoop(
          invoke,
          {
            result: first,
            errorCount: 0,
          },
          MAX_TRANSCRIBE_POLLS
        )
      : {
          result: first,
          errorCount: 0,
        };
    const result = pollState.result;

    if (result.pending) {
      return {
        transcriptionId: result.transcriptionId?.toString(),
        text: result.text ?? null,
        pending: true,
        message: pollState.lastErrorMessage
          ? `Transcription is still processing. Last polling error: ${pollState.lastErrorMessage}`
          : "Transcription is still processing. Try again later.",
      };
    }

    return {
      transcriptionId: result.transcriptionId?.toString(),
      text: result.text ?? null,
      pending: false,
      ...(result.trialRemainsNum !== undefined && {
        trialRemainsNum: result.trialRemainsNum,
        trialRemainsUntilDate: result.trialRemainsUntilDate,
      }),
    };
  } catch (error: unknown) {
    const code = telegramErrorMessage(error);
    if (code === "PREMIUM_ACCOUNT_REQUIRED") {
      throw new Error(
        "Telegram Premium is required to transcribe audio messages."
      );
    }
    if (code === "MSG_ID_INVALID") {
      throw new Error(
        "Invalid message ID — the message may not exist or is not voice/audio."
      );
    }
    throw error;
  }
}

export async function gramJsUpdateProfile(
  client: TelegramClient,
  input: { firstName?: string; lastName?: string; about?: string }
): Promise<UpdateProfileResult> {
  const updated: UpdateProfileResult["updated"] = {};
  await client.invoke(
    new Api.account.UpdateProfile({
      ...(input.firstName !== undefined ? { firstName: input.firstName } : {}),
      ...(input.lastName !== undefined ? { lastName: input.lastName } : {}),
      ...(input.about !== undefined ? { about: input.about } : {}),
    })
  );
  if (input.firstName !== undefined || input.lastName !== undefined) {
    updated.name = true;
  }
  if (input.about !== undefined) {
    updated.about = true;
  }
  return {
    updated,
    firstName: input.firstName,
    lastName: input.lastName,
    about: input.about,
  };
}

export async function gramJsSetBio(
  client: TelegramClient,
  input: { bio: string }
): Promise<SetBioResult> {
  await client.invoke(
    new Api.account.UpdateProfile({
      about: input.bio,
    })
  );
  return { bio: input.bio, length: input.bio.length };
}

export async function gramJsSetOwnUsername(
  client: TelegramClient,
  input: { username: string }
): Promise<SetOwnUsernameResult> {
  await client.invoke(
    new Api.account.UpdateUsername({
      username: input.username || "",
    })
  );
  const u = input.username || "";
  return {
    username: u.length > 0 ? u : null,
    link: u.length > 0 ? `https://t.me/${u}` : null,
  };
}

export async function gramJsSetPersonalChannel(
  client: TelegramClient,
  input: { channelId?: string }
): Promise<SetPersonalChannelResult> {
  let channel: Api.TypeEntityLike;
  let action: SetPersonalChannelResult["action"];
  if (input.channelId) {
    channel = await client.getEntity(input.channelId);
    action = "set";
  } else {
    channel = new Api.InputChannelEmpty();
    action = "removed";
  }
  await client.invoke(new Api.account.UpdatePersonalChannel({ channel }));
  return { action, channelId: input.channelId ?? null };
}

export async function gramJsGetFolders(
  client: TelegramClient
): Promise<GetFoldersResult> {
  const dialogFilters = (await client.invoke(
    new Api.messages.GetDialogFilters()
  )) as Api.messages.DialogFilters;
  const filterList = dialogFilters.filters ?? [];
  const folders = filterList
    .filter((f): f is Api.DialogFilter => f.className === "DialogFilter")
    .map((filter) => ({
      id: filter.id,
      title: folderTitleText(filter.title),
      emoji: filter.emoticon ?? null,
      pinnedPeersCount: filter.pinnedPeers?.length ?? 0,
      includedPeersCount: filter.includePeers?.length ?? 0,
      excludedPeersCount: filter.excludePeers?.length ?? 0,
      includeContacts: filter.contacts ?? false,
      includeNonContacts: filter.nonContacts ?? false,
      includeGroups: filter.groups ?? false,
      includeBroadcasts: filter.broadcasts ?? false,
      includeBots: filter.bots ?? false,
      excludeMuted: filter.excludeMuted ?? false,
      excludeRead: filter.excludeRead ?? false,
      excludeArchived: filter.excludeArchived ?? false,
    }));
  return { folders, totalCount: folders.length };
}

export async function gramJsCreateFolder(
  client: TelegramClient,
  input: {
    title: string;
    emoji?: string;
    includeContacts?: boolean;
    includeNonContacts?: boolean;
    includeGroups?: boolean;
    includeBroadcasts?: boolean;
    includeBots?: boolean;
  }
): Promise<CreateFolderResult> {
  const includeContacts = input.includeContacts ?? false;
  const includeNonContacts = input.includeNonContacts ?? false;
  const includeGroups = input.includeGroups ?? false;
  const includeBroadcasts = input.includeBroadcasts ?? false;
  const includeBots = input.includeBots ?? false;

  const dialogFilters = (await client.invoke(
    new Api.messages.GetDialogFilters()
  )) as Api.messages.DialogFilters;
  const filters = dialogFilters.filters ?? [];
  const usedIds = filters
    .filter((f): f is Api.DialogFilter => "id" in f && typeof f.id === "number")
    .map((f) => f.id);
  const newId = usedIds.length > 0 ? Math.max(...usedIds) + 1 : 2;

  const filterData: ConstructorParameters<typeof Api.DialogFilter>[0] = {
    id: newId,
    title: new Api.TextWithEntities({ text: input.title, entities: [] }),
    pinnedPeers: [],
    includePeers: [],
    excludePeers: [],
    contacts: includeContacts,
    nonContacts: includeNonContacts,
    groups: includeGroups,
    broadcasts: includeBroadcasts,
    bots: includeBots,
    excludeMuted: false,
    excludeRead: false,
    excludeArchived: false,
    ...(input.emoji ? { emoticon: input.emoji } : {}),
  };

  await client.invoke(
    new Api.messages.UpdateDialogFilter({
      id: newId,
      filter: new Api.DialogFilter(filterData),
    })
  );

  return { folderId: newId, title: input.title, emoji: input.emoji };
}

export async function gramJsAddChatToFolder(
  client: TelegramClient,
  input: { folderId: number; chatId: string }
): Promise<AddChatToFolderResult> {
  const filtersResult = (await client.invoke(
    new Api.messages.GetDialogFilters()
  )) as Api.messages.DialogFilters;
  const filterList = filtersResult.filters ?? [];
  const folder = filterList.find(
    (f) => "id" in f && f.id === input.folderId
  );

  if (!folder || folder.className !== "DialogFilter") {
    throw new Error(`Folder with ID ${String(input.folderId)} not found`);
  }

  const inputPeer = await client.getInputEntity(input.chatId);
  const updatedIncludePeers = [...(folder.includePeers ?? [])];
  updatedIncludePeers.push(inputPeer);

  const updatedFilter = new Api.DialogFilter({
    ...folder,
    includePeers: updatedIncludePeers,
  });

  await client.invoke(
    new Api.messages.UpdateDialogFilter({
      id: input.folderId,
      filter: updatedFilter,
    })
  );

  return {
    folderId: input.folderId,
    folderTitle: folderTitleText(folder.title),
    chatId: input.chatId,
    totalChatsInFolder: updatedIncludePeers.length,
  };
}

export async function gramJsBlockUser(
  client: TelegramClient,
  input: { userId: string }
): Promise<BlockUserResult> {
  const userEntity = await client.getInputEntity(input.userId);
  await client.invoke(
    new Api.contacts.Block({
      id: userEntity,
    })
  );
  return { userId: input.userId, blocked: true };
}

export async function gramJsGetBlocked(
  client: TelegramClient,
  input: { limit?: number }
): Promise<GetBlockedResult> {
  const limit = input.limit ?? 50;
  const result = await client.invoke(
    new Api.contacts.GetBlocked({
      offset: 0,
      limit,
    })
  );
  const blocked = result.users.map((user) => {
    const u = user as Api.User;
    return {
      userId: u.id?.toString(),
      username: u.username ?? null,
      firstName: u.firstName ?? null,
      lastName: u.lastName ?? null,
      isBot: u.bot ?? false,
    };
  });
  return { count: blocked.length, blocked };
}

export async function gramJsGetCommonChats(
  client: TelegramClient,
  input: { userId: string; limit?: number }
): Promise<GetCommonChatsResult> {
  const limit = input.limit ?? 50;
  const userEntity = await client.getInputEntity(input.userId);
  const result = await client.invoke(
    new Api.messages.GetCommonChats({
      userId: userEntity,
      maxId: helpers.returnBigInt(0),
      limit,
    })
  );
  const chats = result.chats.map((chat) => {
    const c = chat as Api.Channel | Api.Chat;
    if (c.className === "Channel") {
      const ch = c as Api.Channel;
      return {
        chatId: ch.id?.toString(),
        title: ch.title ?? null,
        username: ch.username ?? null,
        isChannel: ch.broadcast ?? false,
        isMegagroup: ch.megagroup ?? false,
        membersCount: ch.participantsCount ?? null,
      };
    }
    const g = c as Api.Chat;
    return {
      chatId: g.id?.toString(),
      title: g.title ?? null,
      username: null,
      isChannel: false,
      isMegagroup: false,
      membersCount: g.participantsCount ?? null,
    };
  });
  return { userId: input.userId, count: chats.length, chats };
}

function userDisplayName(user: Api.User): string {
  if (user.firstName) {
    return `${user.firstName}${user.lastName ? ` ${user.lastName}` : ""}`;
  }
  return user.username ?? `User ${user.id.toString()}`;
}

export async function gramJsGetUserInfo(
  client: TelegramClient,
  input: { userId?: string; username?: string }
): Promise<GetUserInfoResult> {
  let entity: Api.User;
  if (input.username) {
    const clean = input.username.replace(/^@/, "");
    entity = (await client.getEntity(clean)) as Api.User;
  } else if (input.userId) {
    entity = (await client.getEntity(input.userId)) as Api.User;
  } else {
    throw new Error("Must provide either userId or username");
  }

  if (entity.className !== "User") {
    throw new Error(`Entity is not a user (got ${entity.className})`);
  }

  let fullUser: Api.users.UserFull | null = null;
  try {
    fullUser = (await client.invoke(
      new Api.users.GetFullUser({
        id: entity,
      })
    )) as Api.users.UserFull;
  } catch {
    fullUser = null;
  }

  let photoInfo: { hasPhoto: true; photoId: string } | null = null;
  if (entity.photo && entity.photo.className === "UserProfilePhoto") {
    const photo = entity.photo as Api.UserProfilePhoto;
    photoInfo = {
      hasPhoto: true,
      photoId: photo.photoId.toString(),
    };
  }

  const userInfo: GetUserInfoResult = {
    id: entity.id.toString(),
    username: entity.username ?? null,
    firstName: entity.firstName ?? null,
    lastName: entity.lastName ?? null,
    fullName: userDisplayName(entity),
    phone: entity.phone ?? null,
    isBot: entity.bot ?? false,
    isPremium: entity.premium ?? false,
    isVerified: entity.verified ?? false,
    isScam: entity.scam ?? false,
    isFake: entity.fake ?? false,
    isRestricted: entity.restricted ?? false,
    accessHash: entity.accessHash?.toString(),
    photo: photoInfo,
  };

  if (fullUser?.fullUser) {
    const full = fullUser.fullUser;
    userInfo.bio = full.about ?? null;
    userInfo.commonChatsCount = full.commonChatsCount ?? 0;
    userInfo.canPinMessage = full.canPinMessage ?? false;
    userInfo.blocked = full.blocked ?? false;
    userInfo.voiceMessagesForbidden = full.voiceMessagesForbidden ?? false;
  }

  return userInfo;
}

export async function gramJsResolveUsername(
  client: TelegramClient,
  input: { username: string }
): Promise<ResolveUsernameResult> {
  const cleanUsername = input.username.replace(/^@/, "").toLowerCase();
  if (!cleanUsername) {
    throw new Error("Username cannot be empty");
  }

  try {
    const result = await client.invoke(
      new Api.contacts.ResolveUsername({
        username: cleanUsername,
      })
    );

    let entityType: string | null = null;
    let entity: Record<string, unknown> = {};

    if (result.users && result.users.length > 0) {
      const user = result.users[0] as Api.User;
      entityType = user.bot ? "bot" : "user";
      entity = {
        id: user.id.toString(),
        username: user.username,
        firstName: user.firstName ?? null,
        lastName: user.lastName ?? null,
        isBot: user.bot ?? false,
        isPremium: user.premium ?? false,
        isVerified: user.verified ?? false,
      };
    } else if (result.chats && result.chats.length > 0) {
      const chat = result.chats[0];
      if (chat.className === "Channel") {
        const channel = chat as Api.Channel;
        entityType = channel.megagroup ? "group" : "channel";
        entity = {
          id: channel.id.toString(),
          username: channel.username,
          title: channel.title,
          isVerified: channel.verified ?? false,
          participantsCount: channel.participantsCount ?? null,
          isMegagroup: channel.megagroup ?? false,
          isBroadcast: channel.broadcast ?? false,
        };
      } else if (chat.className === "Chat") {
        const group = chat as Api.Chat;
        entityType = "group";
        entity = {
          id: group.id.toString(),
          title: group.title,
          participantsCount: group.participantsCount ?? null,
        };
      }
    }

    return {
      username: cleanUsername,
      exists: true,
      type: entityType,
      entity,
    };
  } catch (error: unknown) {
    const msg =
      error instanceof Error ? error.message : String(error);
    const code = telegramErrorMessage(error);
    if (
      code === "USERNAME_NOT_OCCUPIED" ||
      msg.includes("USERNAME_NOT_OCCUPIED") ||
      msg.includes("No user has")
    ) {
      return {
        username: cleanUsername,
        exists: false,
        type: null,
        available: true,
      };
    }
    if (msg.includes("USERNAME_INVALID") || code === "USERNAME_INVALID") {
      throw new Error(`Invalid username format: @${cleanUsername}`);
    }
    throw error;
  }
}

export async function gramJsSendStory(
  client: TelegramClient,
  input: {
    mediaPath: string;
    caption?: string;
    privacy?: "everyone" | "contacts" | "close_friends";
    duration?: number;
  }
): Promise<SendStoryResult> {
  const filePath = input.mediaPath;
  const fileName = basename(filePath);
  const fileSize = statSync(filePath).size;
  const fileBuffer = readFileSync(filePath);
  const lowerFilePath = filePath.toLowerCase();
  const isVideo = lowerFilePath.endsWith(".mp4");
  const isPhoto =
    lowerFilePath.endsWith(".jpg") ||
    lowerFilePath.endsWith(".jpeg") ||
    lowerFilePath.endsWith(".png");

  if (!isVideo && !isPhoto) {
    throw new Error(
      "Story media must be a .jpg, .jpeg, .png, or .mp4 file"
    );
  }

  const customFile = new CustomFile(fileName, fileSize, filePath, fileBuffer);
  const uploadedFile = await client.uploadFile({
    file: customFile,
    workers: 1,
  });

  let inputMedia: Api.TypeInputMedia;
  if (isVideo) {
    inputMedia = new Api.InputMediaUploadedDocument({
      file: uploadedFile,
      mimeType: "video/mp4",
      attributes: [
        new Api.DocumentAttributeVideo({
          duration: input.duration ?? 0,
          w: 720,
          h: 1280,
          supportsStreaming: true,
        }),
        new Api.DocumentAttributeFilename({ fileName: fileName }),
      ],
    });
  } else {
    inputMedia = new Api.InputMediaUploadedPhoto({
      file: uploadedFile,
    });
  }

  const privacy = input.privacy ?? "everyone";
  let privacyRules: Api.TypeInputPrivacyRule[];
  if (privacy === "contacts") {
    privacyRules = [new Api.InputPrivacyValueAllowContacts()];
  } else if (privacy === "close_friends") {
    privacyRules = [new Api.InputPrivacyValueAllowCloseFriends()];
  } else {
    privacyRules = [new Api.InputPrivacyValueAllowAll()];
  }

  const result = await client.invoke(
    new Api.stories.SendStory({
      peer: "me",
      media: inputMedia,
      caption: input.caption ?? "",
      privacyRules,
      randomId: helpers.generateRandomBigInt(),
    })
  );

  const storyUpdate =
    result instanceof Api.Updates
      ? result.updates.find((u) => u.className === "UpdateStory")
      : undefined;
  const storyId =
    storyUpdate && "story" in storyUpdate && storyUpdate.story
      ? (storyUpdate.story as { id?: number }).id ?? null
      : null;

  return {
    storyId,
    privacy,
    expiresAt: new Date(Date.now() + 24 * 60 * 60 * 1000).toISOString(),
  };
}
