/** Public channel username: 5–32 chars, alphanumeric + underscore, no leading/trailing underscore. */
export const CHANNEL_PUBLIC_USERNAME_REGEX =
  /^[a-zA-Z0-9][a-zA-Z0-9_]{3,30}[a-zA-Z0-9]$/;

export function invalidPublicUsernameMessage(): string {
  return "Invalid username format. Must be 5-32 characters, alphanumeric and underscores only, cannot start/end with underscore.";
}
