import { z } from "zod";
import type { TelegramBridge } from "../../bridge.js";
import type { GetChatInfoResult } from "../../types.js";

export const getChatInfoToolShape = {
  chatId: z
    .string()
    .trim()
    .min(1)
    .describe(
      "The chat ID or username to get info about. Examples: '-1001234567890', '@channelname', '123456789'"
    ),
} as const;

export const getChatInfoInputSchema = z.object(getChatInfoToolShape);

export async function handleGetChatInfo(
  bridge: TelegramBridge,
  input: z.infer<typeof getChatInfoInputSchema>
): Promise<GetChatInfoResult> {
  const parsed = getChatInfoInputSchema.parse(input);
  return bridge.getChatInfo({ chatId: parsed.chatId });
}
