import { z } from "zod";
import type { TelegramBridge } from "../../bridge.js";
import type { GetAdminedChannelsResult } from "../../types.js";

export const getAdminedChannelsToolShape = {
  forPersonal: z
    .boolean()
    .optional()
    .describe(
      "If true, filter for channels suitable as personal channel"
    ),
} as const;

export const getAdminedChannelsInputSchema = z.object(
  getAdminedChannelsToolShape
);

export async function handleGetAdminedChannels(
  bridge: TelegramBridge,
  input: z.infer<typeof getAdminedChannelsInputSchema>
): Promise<GetAdminedChannelsResult> {
  const parsed = getAdminedChannelsInputSchema.parse(input);
  return bridge.getAdminedChannels({ forPersonal: parsed.forPersonal });
}
