import { z } from "zod";
import type { TelegramBridge } from "../../bridge.js";

export const getBlockedToolShape = {
  limit: z.number().int().min(1).max(100).optional(),
} as const;

export const getBlockedInputSchema = z.object(getBlockedToolShape);

export async function handleGetBlocked(
  bridge: TelegramBridge,
  input: z.infer<typeof getBlockedInputSchema>
): Promise<Awaited<ReturnType<TelegramBridge["getBlocked"]>>> {
  const parsed = getBlockedInputSchema.parse(input);
  return bridge.getBlocked({ limit: parsed.limit });
}
