import { z } from "zod";
import type { TelegramBridge } from "../../bridge.js";

export const getParticipantsToolShape = {
  chatId: z
    .string()
    .trim()
    .min(1)
    .describe("The chat/channel/group ID to get participants from"),
  filter: z
    .enum(["all", "admins", "banned", "bots"])
    .optional()
    .describe(
      "Filter participants: all (default), admins, banned, or bots. The banned filter is only supported for supergroups/channels."
    ),
  limit: z
    .number()
    .int()
    .min(1)
    .max(200)
    .optional()
    .describe("Max participants to return (default 100, max 200)"),
} as const;

export const getParticipantsInputSchema = z.object(getParticipantsToolShape);

export async function handleGetParticipants(
  bridge: TelegramBridge,
  input: z.infer<typeof getParticipantsInputSchema>
): Promise<Awaited<ReturnType<TelegramBridge["getParticipants"]>>> {
  const parsed = getParticipantsInputSchema.parse(input);
  return bridge.getParticipants({
    chatId: parsed.chatId,
    filter: parsed.filter ?? "all",
    limit: parsed.limit ?? 100,
  });
}
