import { z } from "zod";
import type { TelegramBridge } from "../../bridge.js";

export const kickUserToolShape = {
  chat_id: z
    .string()
    .trim()
    .min(1)
    .describe("Group/channel ID or username"),
  user_id: z
    .string()
    .trim()
    .min(1)
    .describe("User ID or username to remove"),
} as const;

export const kickUserInputSchema = z.object(kickUserToolShape);

export async function handleKickUser(
  bridge: TelegramBridge,
  input: z.infer<typeof kickUserInputSchema>
): Promise<Awaited<ReturnType<TelegramBridge["kickUser"]>>> {
  const parsed = kickUserInputSchema.parse(input);
  return bridge.kickUser(parsed);
}

export const banUserToolShape = {
  chat_id: z
    .string()
    .trim()
    .min(1)
    .describe("Supergroup/channel ID or username"),
  user_id: z.string().trim().min(1).describe("User ID or username to ban"),
  delete_messages: z
    .boolean()
    .optional()
    .describe("Delete all messages from this user in the chat (default false)"),
  duration_hours: z
    .number()
    .int()
    .min(1)
    .optional()
    .describe("Ban duration in hours; omit for permanent ban"),
} as const;

export const banUserInputSchema = z.object(banUserToolShape);

export async function handleBanUser(
  bridge: TelegramBridge,
  input: z.infer<typeof banUserInputSchema>
): Promise<Awaited<ReturnType<TelegramBridge["banUser"]>>> {
  const parsed = banUserInputSchema.parse(input);
  return bridge.banUser({
    chat_id: parsed.chat_id,
    user_id: parsed.user_id,
    delete_messages: parsed.delete_messages,
    duration_hours: parsed.duration_hours,
  });
}

export const unbanUserToolShape = {
  chat_id: z
    .string()
    .trim()
    .min(1)
    .describe("Supergroup/channel ID or username"),
  user_id: z.string().trim().min(1).describe("User ID or username to unban"),
} as const;

export const unbanUserInputSchema = z.object(unbanUserToolShape);

export async function handleUnbanUser(
  bridge: TelegramBridge,
  input: z.infer<typeof unbanUserInputSchema>
): Promise<Awaited<ReturnType<TelegramBridge["unbanUser"]>>> {
  const parsed = unbanUserInputSchema.parse(input);
  return bridge.unbanUser(parsed);
}
