import { z } from "zod";
import type { TelegramBridge } from "../../bridge.js";

export const replyKeyboardToolShape = {
  chatId: z.string().trim().min(1).describe("Chat ID to send the keyboard to"),
  text: z.string().min(1).describe("Message text shown with the keyboard"),
  buttons: z
    .array(z.array(z.string().min(1)).min(1))
    .min(1)
    .describe("Rows of button labels; each inner array is one row"),
  oneTime: z
    .boolean()
    .optional()
    .default(false)
    .describe("Hide keyboard after a tap (default false)"),
  resize: z
    .boolean()
    .optional()
    .default(true)
    .describe("Resize keyboard to fit buttons (default true)"),
  selective: z
    .boolean()
    .optional()
    .default(false)
    .describe("Keyboard only for mentioned/reply targets (default false)"),
  replyToId: z.number().int().optional().describe("Optional message ID to reply to"),
} as const;

export const replyKeyboardInputSchema = z.object(replyKeyboardToolShape);

export async function handleReplyKeyboard(
  bridge: TelegramBridge,
  input: z.infer<typeof replyKeyboardInputSchema>
): Promise<Awaited<ReturnType<TelegramBridge["sendReplyKeyboard"]>>> {
  const parsed = replyKeyboardInputSchema.parse(input);
  return bridge.sendReplyKeyboard(parsed);
}
