import { z } from "zod";
import type { TelegramBridge } from "../../bridge.js";
import type { MarkAsReadResult } from "../../types.js";

export const markAsReadToolShape = {
  chatId: z.string().trim().min(1).describe("The chat ID to mark as read"),
  messageId: z
    .number()
    .int()
    .optional()
    .describe(
      "Mark as read up to this message ID. If not provided, marks all messages as read."
    ),
  clearMentions: z
    .boolean()
    .optional()
    .default(true)
    .describe("Also clear the mentions badge. Default: true"),
} as const;

export const markAsReadInputSchema = z.object(markAsReadToolShape);

export async function handleMarkAsRead(
  bridge: TelegramBridge,
  input: z.infer<typeof markAsReadInputSchema>
): Promise<MarkAsReadResult> {
  const parsed = markAsReadInputSchema.parse(input);
  return bridge.markAsRead({
    chatId: parsed.chatId,
    messageId: parsed.messageId,
    clearMentions: parsed.clearMentions,
  });
}
