import { Api, helpers } from "telegram";
import type { TelegramClient } from "telegram";

function singleEntityFromGetEntity(result: unknown, notFoundMessage: string) {
  if (Array.isArray(result)) {
    const first = result[0];
    if (!first) {
      throw new Error(notFoundMessage);
    }
    return first;
  }
  return result;
}
import { CHANNEL_PUBLIC_USERNAME_REGEX } from "./tools/chats/channel-username.js";
import type {
  CheckChannelUsernameResult,
  CreateChannelResult,
  EditChannelInfoResult,
  GetAdminedChannelsResult,
  GetChatInfoResult,
  InviteToChannelResult,
  JoinChannelResult,
  LeaveChannelResult,
  MarkAsReadResult,
  SetChannelUsernameResult,
} from "./types.js";

function getGramErrorMessage(error: unknown): string {
  if (error instanceof Error) {
    return error.message;
  }
  if (
    typeof error === "object" &&
    error !== null &&
    "errorMessage" in error &&
    typeof (error as { errorMessage: unknown }).errorMessage === "string"
  ) {
    return (error as { errorMessage: string }).errorMessage;
  }
  return String(error);
}

function errorTextIncludes(error: unknown, needle: string): boolean {
  const msg = getGramErrorMessage(error);
  return msg.includes(needle);
}

function extractInviteHash(input: string): string | null {
  const patterns = [
    /t\.me\/\+([A-Za-z0-9_-]+)/,
    /t\.me\/joinchat\/([A-Za-z0-9_-]+)/,
    /tg:\/\/join\?invite=([A-Za-z0-9_-]+)/,
  ];
  for (const pattern of patterns) {
    const match = input.match(pattern);
    if (match) {
      return match[1] ?? null;
    }
  }
  return null;
}

export async function gramJsGetChatInfo(
  client: TelegramClient,
  chatId: string
): Promise<GetChatInfoResult> {
  let entity: ReturnType<typeof singleEntityFromGetEntity>;
  try {
    entity = singleEntityFromGetEntity(
      await client.getEntity(chatId),
      `Could not find chat "${chatId}"`
    );
  } catch {
    throw new Error(`Could not find chat "${chatId}"`);
  }

  const isChannel =
    entity.className === "Channel" || entity.className === "ChannelForbidden";
  const isChat =
    entity.className === "Chat" || entity.className === "ChatForbidden";
  const isUser = entity.className === "User";

  const entityId =
    "id" in entity && entity.id != null ? entity.id.toString() : chatId;

  let chatInfo: Record<string, unknown> = {
    id: entityId,
    type: isChannel ? "channel" : isChat ? "group" : isUser ? "user" : "unknown",
  };

  if (isUser) {
    const user = entity as Api.User;
    chatInfo = {
      ...chatInfo,
      username: user.username || null,
      firstName: user.firstName || null,
      lastName: user.lastName || null,
      phone: user.phone || null,
      isBot: user.bot || false,
      isPremium: user.premium || false,
      isVerified: user.verified || false,
      fullName:
        [user.firstName, user.lastName].filter(Boolean).join(" ") || null,
    };
  } else if (isChannel || isChat) {
    try {
      if (isChannel) {
        const fullChannel = await client.invoke(
          new Api.channels.GetFullChannel({
            channel: entity as Api.Channel,
          })
        );

        const channel = entity as Api.Channel;
        const fullChat = fullChannel.fullChat as Api.ChannelFull;

        chatInfo = {
          ...chatInfo,
          title: channel.title || null,
          username: channel.username || null,
          description: fullChat.about || null,
          participantsCount: fullChat.participantsCount || null,
          adminsCount: fullChat.adminsCount || null,
          isBroadcast: channel.broadcast || false,
          isMegagroup: channel.megagroup || false,
          isVerified: channel.verified || false,
          isRestricted: channel.restricted || false,
          hasLink: Boolean(fullChat.linkedChatId),
          linkedChatId: fullChat.linkedChatId?.toString() || null,
        };
      } else {
        const chat = entity as Api.Chat;
        const fullChatResult = await client.invoke(
          new Api.messages.GetFullChat({
            chatId: chat.id,
          })
        );

        const fullChat = fullChatResult.fullChat as Api.ChatFull;

        chatInfo = {
          ...chatInfo,
          title: chat.title || null,
          description: fullChat.about || null,
          participantsCount: chat.participantsCount || null,
          isDeactivated: chat.deactivated || false,
        };
      }
    } catch {
      chatInfo = {
        ...chatInfo,
        title:
          entity instanceof Api.Channel
            ? entity.title
            : entity instanceof Api.Chat
              ? entity.title
              : null,
        username: entity instanceof Api.Channel ? entity.username : null,
        note: "Could not fetch full chat info (may lack permissions)",
      };
    }
  }

  return chatInfo;
}

export async function gramJsMarkAsRead(
  client: TelegramClient,
  input: { chatId: string; messageId?: number; clearMentions: boolean }
): Promise<MarkAsReadResult> {
  let entity: ReturnType<typeof singleEntityFromGetEntity>;
  try {
    entity = singleEntityFromGetEntity(
      await client.getEntity(input.chatId),
      `Could not find chat "${input.chatId}"`
    );
  } catch {
    throw new Error(`Could not find chat "${input.chatId}"`);
  }

  await client.markAsRead(entity, input.messageId, {
    clearMentions: input.clearMentions,
  });

  return {
    chatId: input.chatId,
    messageId: input.messageId ?? "all",
    mentionsCleared: input.clearMentions,
    message: input.messageId
      ? `Marked messages up to ${input.messageId} as read`
      : "Marked all messages as read",
  };
}

export async function gramJsJoinChannel(
  client: TelegramClient,
  channel: string
): Promise<JoinChannelResult> {
  try {
    const inviteHash = extractInviteHash(channel);

    if (inviteHash) {
      const checkResult = await client.invoke(
        new Api.messages.CheckChatInvite({ hash: inviteHash })
      );

      if (checkResult instanceof Api.ChatInviteAlready) {
        const chat = checkResult.chat;
        const chatTitle =
          chat instanceof Api.Channel || chat instanceof Api.Chat
            ? chat.title
            : channel;
        return {
          channel,
          channelId: chat.id?.toString() || null,
          channelTitle: chatTitle,
          message: `Already a member of ${chatTitle}`,
        };
      }

      const updates = await client.invoke(
        new Api.messages.ImportChatInvite({ hash: inviteHash })
      );

      const chats =
        updates instanceof Api.Updates || updates instanceof Api.UpdatesCombined
          ? updates.chats
          : [];
      const joinedChat = chats[0];
      const chatTitle =
        joinedChat instanceof Api.Channel || joinedChat instanceof Api.Chat
          ? joinedChat.title
          : channel;
      const chatId = joinedChat?.id?.toString() || null;

      return {
        channel,
        channelId: chatId,
        channelTitle: chatTitle,
        message: `Successfully joined ${chatTitle}`,
      };
    }

    let channelEntity: ReturnType<typeof singleEntityFromGetEntity>;
    try {
      channelEntity = singleEntityFromGetEntity(
        await client.getEntity(channel),
        `Could not find channel "${channel}"`
      );
    } catch {
      const clean = channel.replace(/^@/, "");
      let resolvedEntity: ReturnType<typeof singleEntityFromGetEntity> | undefined;
      try {
        const resolved = await client.invoke(
          new Api.contacts.ResolveUsername({ username: clean })
        );
        resolvedEntity = resolved.chats[0] || resolved.users[0];
      } catch {
        // not found
      }
      if (!resolvedEntity) {
        throw new Error(
          `Could not find channel "${channel}". Make sure it's a public channel or you have access to it.`
        );
      }
      channelEntity = resolvedEntity;
    }

    await client.invoke(
      new Api.channels.JoinChannel({
        channel: channelEntity,
      })
    );

    const channelTitle =
      channelEntity instanceof Api.Channel
        ? channelEntity.title
        : channelEntity instanceof Api.User
          ? channelEntity.username
          : channel;
    const channelId = channelEntity.id?.toString() || null;

    return {
      channel,
      channelId,
      channelTitle,
      message: `Successfully joined ${channelTitle}`,
    };
  } catch (error) {
    if (errorTextIncludes(error, "USER_ALREADY_PARTICIPANT")) {
      return {
        channel,
        message: `Already a member of ${channel}`,
      };
    }
    if (errorTextIncludes(error, "INVITE_HASH_INVALID")) {
      throw new Error(
        "Invalid invite link. The link may be malformed or revoked."
      );
    }
    if (errorTextIncludes(error, "INVITE_HASH_EXPIRED")) {
      throw new Error("This invite link has expired.");
    }
    if (errorTextIncludes(error, "INVITE_REQUEST_SENT")) {
      return {
        channel,
        message: "Join request sent. Waiting for admin approval.",
      };
    }
    if (errorTextIncludes(error, "CHANNELS_TOO_MUCH")) {
      throw new Error(
        "You've joined too many channels. Leave some before joining new ones."
      );
    }
    throw new Error(getGramErrorMessage(error));
  }
}

export async function gramJsLeaveChannel(
  client: TelegramClient,
  channel: string
): Promise<LeaveChannelResult> {
  try {
    let channelEntity: ReturnType<typeof singleEntityFromGetEntity>;
    try {
      channelEntity = singleEntityFromGetEntity(
        await client.getEntity(channel),
        `Could not find channel "${channel}". Make sure it exists and you have access to it.`
      );
    } catch {
      throw new Error(
        `Could not find channel "${channel}". Make sure it exists and you have access to it.`
      );
    }

    await client.invoke(
      new Api.channels.LeaveChannel({
        channel: channelEntity,
      })
    );

    const channelTitle =
      channelEntity instanceof Api.Channel
        ? channelEntity.title
        : channelEntity instanceof Api.User
          ? channelEntity.username
          : channel;
    const channelId = channelEntity.id?.toString() || null;

    return {
      channel,
      channelId,
      channelTitle,
      message: `Successfully left ${channelTitle}`,
    };
  } catch (error) {
    if (errorTextIncludes(error, "USER_NOT_PARTICIPANT")) {
      return {
        channel,
        message: `Not a member of ${channel}`,
      };
    }
    if (errorTextIncludes(error, "CHANNEL_PRIVATE")) {
      throw new Error("Channel is private or you don't have access to it");
    }
    throw new Error(getGramErrorMessage(error));
  }
}

export async function gramJsCreateChannel(
  client: TelegramClient,
  input: {
    title: string;
    about: string;
    megagroup: boolean;
    username?: string;
  }
): Promise<CreateChannelResult> {
  const { title, about, megagroup, username } = input;

  const result = await client.invoke(
    new Api.channels.CreateChannel({
      title,
      about,
      megagroup,
      broadcast: !megagroup,
    })
  );

  const chats =
    result instanceof Api.Updates || result instanceof Api.UpdatesCombined
      ? result.chats
      : [];
  const channel = chats[0];

  const data: CreateChannelResult = {
    channelId: channel?.id?.toString() ?? "unknown",
    title,
    type: megagroup ? "megagroup" : "channel",
    accessHash:
      channel && "accessHash" in channel && channel.accessHash !== undefined
        ? channel.accessHash.toString()
        : undefined,
  };

  if (username && channel) {
    const clean = username.replace(/^@/, "");

    if (!CHANNEL_PUBLIC_USERNAME_REGEX.test(clean)) {
      data.usernameError =
        "Invalid username format. Must be 5-32 characters, alphanumeric and underscores only, cannot start/end with underscore.";
    } else {
      try {
        await client.invoke(
          new Api.channels.UpdateUsername({
            channel: channel as Api.Channel,
            username: clean,
          })
        );
        data.username = clean;
        data.link = `https://t.me/${clean}`;
      } catch (usernameError: unknown) {
        const msg = getGramErrorMessage(usernameError);
        if (msg.includes("USERNAME_OCCUPIED")) {
          data.usernameError = `Username @${clean} is already taken.`;
        } else if (msg.includes("CHANNELS_ADMIN_PUBLIC_TOO_MUCH")) {
          data.usernameError =
            "Too many public channels. Make some private first.";
        } else if (msg.includes("USERNAME_PURCHASE_AVAILABLE")) {
          data.usernameError = `Username @${clean} is available for purchase on fragment.com.`;
        } else {
          data.usernameError = msg;
        }
      }
    }
  }

  return data;
}

export async function gramJsEditChannelInfo(
  client: TelegramClient,
  input: { channelId: string; title?: string; about?: string }
): Promise<EditChannelInfoResult> {
  const { channelId, title, about } = input;

  try {
    const entity = singleEntityFromGetEntity(
      await client.getEntity(channelId),
      `Could not resolve channel "${channelId}"`
    );

    if (entity.className !== "Channel") {
      throw new Error(
        `Entity is not a channel/group (got ${entity.className})`
      );
    }

    const channel = entity as Api.Channel;
    const updates: string[] = [];

    if (title) {
      await client.invoke(
        new Api.channels.EditTitle({
          channel,
          title,
        })
      );
      updates.push(`title → "${title}"`);
    }

    if (about !== undefined) {
      await client.invoke(
        new Api.messages.EditChatAbout({
          peer: channel,
          about,
        })
      );
      updates.push(
        `about → "${about.slice(0, 50)}${about.length > 50 ? "..." : ""}"`
      );
    }

    return {
      channelId: channel.id.toString(),
      channelTitle: title || channel.title,
      updated: updates,
    };
  } catch (error: unknown) {
    if (errorTextIncludes(error, "CHAT_ADMIN_REQUIRED")) {
      throw new Error("You need admin rights to edit this channel");
    }
    if (errorTextIncludes(error, "CHAT_NOT_MODIFIED")) {
      return { message: "No changes made (values are the same)" };
    }
    throw new Error(getGramErrorMessage(error));
  }
}

export async function gramJsInviteToChannel(
  client: TelegramClient,
  input: {
    channelId: string;
    userIds: string[];
    usernames: string[];
  }
): Promise<InviteToChannelResult> {
  const { channelId, userIds, usernames } = input;

  const channelEntity = singleEntityFromGetEntity(
    await client.getEntity(channelId),
    `Could not resolve channel "${channelId}"`
  );

  if (channelEntity.className !== "Channel") {
    throw new Error(
      `Entity is not a channel/group (got ${channelEntity.className})`
    );
  }

  const channel = channelEntity as Api.Channel;

  const users: Api.TypeInputUser[] = [];
  const resolved: string[] = [];
  const failed: string[] = [];

  for (const userId of userIds) {
    try {
      const user = singleEntityFromGetEntity(
        await client.getEntity(userId),
        ""
      );
      if (user.className === "User") {
        const apiUser = user as Api.User;
        users.push(
          new Api.InputUser({
            userId: apiUser.id,
            accessHash: apiUser.accessHash ?? helpers.returnBigInt(0),
          })
        );
        resolved.push(userId);
      } else {
        failed.push(`${userId} (not a user)`);
      }
    } catch {
      failed.push(`${userId} (not found)`);
    }
  }

  for (const username of usernames) {
    const cleanUsername = username.replace("@", "");
    try {
      const user = singleEntityFromGetEntity(
        await client.getEntity(cleanUsername),
        ""
      );
      if (user.className === "User") {
        const apiUser = user as Api.User;
        users.push(
          new Api.InputUser({
            userId: apiUser.id,
            accessHash: apiUser.accessHash ?? helpers.returnBigInt(0),
          })
        );
        resolved.push(`@${cleanUsername}`);
      } else {
        failed.push(`@${cleanUsername} (not a user)`);
      }
    } catch {
      failed.push(`@${cleanUsername} (not found)`);
    }
  }

  if (users.length === 0) {
    throw new Error(
      `Could not resolve any users to invite. Failed: ${failed.join(", ")}`
    );
  }

  try {
    await client.invoke(
      new Api.channels.InviteToChannel({
        channel,
        users,
      })
    );
  } catch (error: unknown) {
    if (errorTextIncludes(error, "CHAT_ADMIN_REQUIRED")) {
      throw new Error(
        "You need admin rights to invite users to this channel"
      );
    }
    if (errorTextIncludes(error, "USER_PRIVACY_RESTRICTED")) {
      throw new Error(
        "User's privacy settings prevent being added to groups"
      );
    }
    if (errorTextIncludes(error, "USER_NOT_MUTUAL_CONTACT")) {
      throw new Error(
        "You can only add mutual contacts to this group"
      );
    }
    if (errorTextIncludes(error, "USERS_TOO_MUCH")) {
      throw new Error("Too many users in the channel");
    }
    throw new Error(getGramErrorMessage(error));
  }

  return {
    channelId: channel.id.toString(),
    channelTitle: channel.title,
    invited: resolved,
    failed: failed.length > 0 ? failed : undefined,
    invitedCount: resolved.length,
    failedCount: failed.length,
  };
}

export async function gramJsGetAdminedChannels(
  client: TelegramClient,
  forPersonal?: boolean
): Promise<GetAdminedChannelsResult> {
  const result = await client.invoke(
    new Api.channels.GetAdminedPublicChannels({
      byLocation: false,
      checkLimit: false,
      forPersonal,
    })
  );

  const chats = ("chats" in result ? result.chats : []) as Api.Channel[];

  const channels = chats.map((ch) => ({
    id: ch.id?.toString(),
    title: ch.title,
    username: ch.username || null,
    participantsCount: ch.participantsCount || null,
    isMegagroup: ch.megagroup || false,
    isBroadcast: ch.broadcast || false,
  }));

  return {
    count: channels.length,
    channels,
  };
}

export async function gramJsCheckChannelUsername(
  client: TelegramClient,
  channelId: string,
  username: string
): Promise<CheckChannelUsernameResult> {
  const clean = username.replace(/^@/, "");

  const entity = singleEntityFromGetEntity(
    await client.getEntity(channelId),
    `Could not resolve channel "${channelId}"`
  );

  if (entity.className !== "Channel") {
    throw new Error(`Entity is not a channel/group (got ${entity.className})`);
  }

  const channel = entity as Api.Channel;

  try {
    const available = await client.invoke(
      new Api.channels.CheckUsername({
        channel,
        username: clean,
      })
    );

    return {
      channelId: channel.id.toString(),
      username: clean,
      available: Boolean(available),
    };
  } catch (error: unknown) {
    const msg = getGramErrorMessage(error);

    if (msg.includes("USERNAME_INVALID")) {
      throw new Error(`Invalid username format: "${username}"`);
    }

    if (msg.includes("CHANNELS_ADMIN_PUBLIC_TOO_MUCH")) {
      throw new Error(
        "You admin too many public channels. Make some channels private before assigning a new public username."
      );
    }

    if (msg.includes("USERNAME_PURCHASE_AVAILABLE")) {
      return {
        channelId,
        username: clean,
        available: false,
        purchaseAvailable: true,
        message: "This username is available for purchase on fragment.com",
      };
    }

    throw new Error(msg);
  }
}

export async function gramJsSetChannelUsername(
  client: TelegramClient,
  channelId: string,
  username: string
): Promise<SetChannelUsernameResult> {
  const clean = username.replace(/^@/, "");

  const entity = singleEntityFromGetEntity(
    await client.getEntity(channelId),
    `Could not resolve channel "${channelId}"`
  );

  if (entity.className !== "Channel") {
    throw new Error(`Entity is not a channel/group (got ${entity.className})`);
  }

  const channel = entity as Api.Channel;

  try {
    await client.invoke(
      new Api.channels.UpdateUsername({
        channel,
        username: clean || "",
      })
    );

    return {
      channelId: channel.id.toString(),
      username: clean || null,
      link: clean ? `https://t.me/${clean}` : null,
    };
  } catch (error: unknown) {
    const msg = getGramErrorMessage(error);

    if (msg.includes("USERNAME_OCCUPIED")) {
      throw new Error("Username is already taken. Please choose another.");
    }

    if (msg.includes("USERNAME_NOT_MODIFIED")) {
      return { message: "No changes made (username is the same)" };
    }

    if (msg.includes("CHAT_ADMIN_REQUIRED")) {
      throw new Error(
        "You need admin rights to change this channel's username."
      );
    }

    if (msg.includes("CHANNELS_ADMIN_PUBLIC_TOO_MUCH")) {
      throw new Error(
        "You admin too many public channels. Make some channels private first."
      );
    }

    if (msg.includes("USERNAME_INVALID")) {
      throw new Error(`Invalid username format: "${username}"`);
    }

    if (msg.includes("USERNAME_PURCHASE_AVAILABLE")) {
      throw new Error(
        `Username @${clean} is available for purchase on fragment.com, not for free assignment.`
      );
    }

    throw new Error(msg);
  }
}
