import { z } from "zod";
import type { TelegramBridge } from "../../bridge.js";
import type { EditChannelInfoResult } from "../../types.js";

export const editChannelInfoToolShape = {
  channelId: z.string().trim().min(1).describe("Channel or group ID to edit"),
  title: z
    .string()
    .min(1)
    .max(255)
    .optional()
    .describe("New title/name for the channel (1-255 chars)"),
  about: z
    .string()
    .max(255)
    .optional()
    .describe("New description/about text (0-255 chars)"),
} as const;

export const editChannelInfoInputSchema = z
  .object(editChannelInfoToolShape)
  .refine((v) => v.title !== undefined || v.about !== undefined, {
    message: "Must provide at least one field to update (title or about)",
  });

export async function handleEditChannelInfo(
  bridge: TelegramBridge,
  input: z.infer<typeof editChannelInfoInputSchema>
): Promise<EditChannelInfoResult> {
  const parsed = editChannelInfoInputSchema.parse(input);
  return bridge.editChannelInfo({
    channelId: parsed.channelId,
    title: parsed.title,
    about: parsed.about,
  });
}
