import { z } from "zod";
import type { TelegramBridge } from "../../bridge.js";
import type { DialogRow } from "../../types.js";

export const getDialogsToolShape = {
  limit: z
    .number()
    .int()
    .min(1)
    .max(100)
    .default(50)
    .describe("Maximum number of dialogs to retrieve (default: 50, max: 100)"),
  archived: z
    .boolean()
    .default(false)
    .describe("If true, get archived chats. If false, get active chats."),
  unreadOnly: z
    .boolean()
    .default(false)
    .describe("If true, only return dialogs with unread messages."),
} as const;

export const getDialogsInputSchema = z.object(getDialogsToolShape);

export async function handleGetDialogs(
  bridge: TelegramBridge,
  input: z.infer<typeof getDialogsInputSchema>
): Promise<{
  dialogs: DialogRow[];
  count: number;
  totalUnread: number;
  totalMentions: number;
  summary: string;
}> {
  const parsed = getDialogsInputSchema.parse(input);

  const dialogs = await bridge.getDialogs({
    limit: parsed.limit,
    archived: parsed.archived,
  });

  const filteredDialogs = parsed.unreadOnly
    ? dialogs.filter((dialog) => dialog.unreadCount > 0)
    : dialogs;
  const totalUnread = filteredDialogs.reduce(
    (sum, dialog) => sum + dialog.unreadCount,
    0
  );
  const totalMentions = filteredDialogs.reduce(
    (sum, dialog) => sum + dialog.unreadMentionsCount,
    0
  );

  return {
    dialogs: filteredDialogs,
    count: filteredDialogs.length,
    totalUnread,
    totalMentions,
    summary: `${filteredDialogs.length} chats, ${totalUnread} unread messages, ${totalMentions} mentions`,
  };
}
