import { z } from "zod";
import type { TelegramBridge } from "../../bridge.js";

export const updateProfileToolShape = {
  firstName: z.string().max(64).optional(),
  lastName: z.string().max(64).optional(),
  about: z.string().max(70).optional(),
} as const;

export const updateProfileInputSchema = z
  .object(updateProfileToolShape)
  .refine(
    (d) =>
      d.firstName !== undefined ||
      d.lastName !== undefined ||
      d.about !== undefined,
    { message: "Provide at least one of firstName, lastName, about" }
  );

export async function handleUpdateProfile(
  bridge: TelegramBridge,
  input: z.infer<typeof updateProfileInputSchema>
): Promise<Awaited<ReturnType<TelegramBridge["updateProfile"]>>> {
  const parsed = updateProfileInputSchema.parse(input);
  return bridge.updateProfile({
    firstName: parsed.firstName,
    lastName: parsed.lastName,
    about: parsed.about,
  });
}
