import { z } from "zod";
import type { TelegramBridge } from "../../bridge.js";

export const createFolderToolShape = {
  title: z.string().min(1).max(12),
  emoji: z.string().optional(),
  includeContacts: z.boolean().optional(),
  includeNonContacts: z.boolean().optional(),
  includeGroups: z.boolean().optional(),
  includeBroadcasts: z.boolean().optional(),
  includeBots: z.boolean().optional(),
} as const;

export const createFolderInputSchema = z.object(createFolderToolShape);

export async function handleCreateFolder(
  bridge: TelegramBridge,
  input: z.infer<typeof createFolderInputSchema>
): Promise<Awaited<ReturnType<TelegramBridge["createFolder"]>>> {
  const parsed = createFolderInputSchema.parse(input);
  return bridge.createFolder({
    title: parsed.title,
    emoji: parsed.emoji,
    includeContacts: parsed.includeContacts,
    includeNonContacts: parsed.includeNonContacts,
    includeGroups: parsed.includeGroups,
    includeBroadcasts: parsed.includeBroadcasts,
    includeBots: parsed.includeBots,
  });
}
