import { z } from "zod";
import type { TelegramBridge } from "../../bridge.js";

export const sendGifToolShape = {
  chatId: z.string().trim().min(1),
  queryId: z.string().trim().min(1).optional(),
  resultId: z.string().trim().min(1).optional(),
  gifPath: z.string().trim().min(1).optional(),
  caption: z.string().optional(),
  replyToId: z.number().int().optional(),
} as const;

export const sendGifInputSchema = z
  .object(sendGifToolShape)
  .refine(
    (d) =>
      (d.queryId !== undefined && d.resultId !== undefined) ||
      d.gifPath !== undefined,
    { message: "Provide queryId+resultId or gifPath" }
  );

export async function handleSendGif(
  bridge: TelegramBridge,
  input: z.infer<typeof sendGifInputSchema>
): Promise<Awaited<ReturnType<TelegramBridge["sendGif"]>>> {
  const parsed = sendGifInputSchema.parse(input);
  return bridge.sendGif({
    chatId: parsed.chatId,
    queryId: parsed.queryId,
    resultId: parsed.resultId,
    gifPath: parsed.gifPath,
    caption: parsed.caption,
    replyToId: parsed.replyToId,
  });
}
