import { z } from "zod";
import type { TelegramBridge } from "../../bridge.js";

export const getFoldersToolShape = {} as const;

export const getFoldersInputSchema = z.object({});

export async function handleGetFolders(
  bridge: TelegramBridge,
  input: z.infer<typeof getFoldersInputSchema>
): Promise<Awaited<ReturnType<TelegramBridge["getFolders"]>>> {
  getFoldersInputSchema.parse(input);
  return bridge.getFolders();
}
