import { z } from "zod";
import type { TelegramBridge } from "../../bridge.js";

export const sendVoiceToolShape = {
  chatId: z.string().trim().min(1),
  voicePath: z
    .string()
    .trim()
    .min(1)
    .optional()
    .describe("Local path to a voice/audio file (OGG, MP3). Required for this MCP tool."),
  text: z
    .string()
    .optional()
    .describe("Reserved for upstream compatibility. TTS is not supported here; use voicePath."),
  caption: z.string().optional(),
  replyToId: z.number().int().optional(),
  duration: z.number().optional(),
  waveform: z.array(z.number()).optional(),
} as const;

export const sendVoiceInputSchema = z
  .object(sendVoiceToolShape)
  .refine((d) => Boolean(d.voicePath), {
    message: "Provide voicePath with a local audio file. TTS text input is not supported.",
  });

export async function handleSendVoice(
  bridge: TelegramBridge,
  input: z.infer<typeof sendVoiceInputSchema>
): Promise<Awaited<ReturnType<TelegramBridge["sendVoice"]>>> {
  const parsed = sendVoiceInputSchema.parse(input);
  if (parsed.text && !parsed.voicePath) {
    throw new Error(
      "TTS is not supported in telegram-mcp; pass voicePath with an audio file"
    );
  }
  if (!parsed.voicePath) {
    throw new Error("voicePath is required");
  }
  return bridge.sendVoice({
    chatId: parsed.chatId,
    voicePath: parsed.voicePath,
    caption: parsed.caption,
    replyToId: parsed.replyToId,
    duration: parsed.duration,
    waveform: parsed.waveform,
  });
}
