import { z } from "zod";
import type { TelegramBridge } from "../../bridge.js";

export const visionAnalyzeToolShape = {
  chatId: z.string().trim().min(1).optional(),
  messageId: z.number().int().optional(),
  filePath: z
    .string()
    .trim()
    .min(1)
    .optional()
    .describe("Workspace-relative or absolute path to an image file"),
  prompt: z.string().optional(),
} as const;

export const visionAnalyzeInputSchema = z
  .object(visionAnalyzeToolShape)
  .refine(
    (d) =>
      Boolean(d.filePath) ||
      (d.chatId !== undefined && d.messageId !== undefined),
    { message: "Provide filePath or both chatId and messageId" }
  );

export async function handleVisionAnalyze(
  bridge: TelegramBridge,
  input: z.infer<typeof visionAnalyzeInputSchema>
): Promise<Awaited<ReturnType<TelegramBridge["visionAnalyze"]>>> {
  const parsed = visionAnalyzeInputSchema.parse(input);
  return bridge.visionAnalyze({
    chatId: parsed.chatId,
    messageId: parsed.messageId,
    filePath: parsed.filePath,
    prompt: parsed.prompt,
  });
}
