import { z } from "zod";
import type { TelegramBridge } from "../../bridge.js";

export const transcribeAudioToolShape = {
  chatId: z
    .string()
    .trim()
    .min(1)
    .describe("Chat ID where the voice/audio message is"),
  messageId: z
    .number()
    .int()
    .describe("Message ID of the voice/audio message"),
} as const;

export const transcribeAudioInputSchema = z.object(transcribeAudioToolShape);

export async function handleTranscribeAudio(
  bridge: TelegramBridge,
  input: z.infer<typeof transcribeAudioInputSchema>
): Promise<Awaited<ReturnType<TelegramBridge["transcribeAudio"]>>> {
  const parsed = transcribeAudioInputSchema.parse(input);
  return bridge.transcribeAudio({
    chatId: parsed.chatId,
    messageId: parsed.messageId,
  });
}
