import { z } from "zod";
import type { TelegramBridge } from "../../bridge.js";
import type { LeaveChannelResult } from "../../types.js";

export const leaveChannelToolShape = {
  channel: z
    .string()
    .trim()
    .min(1)
    .describe(
      "Channel username (with or without @) or numeric channel ID to leave. Examples: '@mychannel', 'mychannel', '-1001234567890'"
    ),
} as const;

export const leaveChannelInputSchema = z.object(leaveChannelToolShape);

export async function handleLeaveChannel(
  bridge: TelegramBridge,
  input: z.infer<typeof leaveChannelInputSchema>
): Promise<LeaveChannelResult> {
  const parsed = leaveChannelInputSchema.parse(input);
  return bridge.leaveChannel({ channel: parsed.channel });
}
