import { McpServer } from "@modelcontextprotocol/sdk/server/mcp.js";
import type { TelegramBridge } from "./bridge.js";
import { registerTelegramTools } from "./registry.js";

export function createTelegramMcpServer(bridge: TelegramBridge): McpServer {
  const server = new McpServer({
    name: "telegram-mcp",
    version: "0.1.0",
  });
  registerTelegramTools(server, bridge);
  return server;
}
