function isMessageIdInvalidError(error: unknown): boolean {
  return (
    typeof error === "object" &&
    error !== null &&
    "errorMessage" in error &&
    (error as { errorMessage: string }).errorMessage === "MESSAGE_ID_INVALID"
  );
}

function dialogRowFromGramJs(dialog: {
  id?: { toString(): string };
  title?: string;
  name?: string;
  unreadCount: number;
  unreadMentionsCount?: number;
  pinned?: boolean;
  archived?: boolean;
  date?: number;
  message?: { message?: string };
  isChannel?: boolean;
  isGroup?: boolean;
}): DialogRow {
  const id = dialog.id?.toString() ?? "";
  const title = dialog.title ?? dialog.name ?? id;
  const type = dialog.isChannel ? "channel" : dialog.isGroup ? "group" : "dm";

  return {
    id,
    title,
    type,
    unreadCount: dialog.unreadCount,
    unreadMentionsCount: dialog.unreadMentionsCount ?? 0,
    isPinned: dialog.pinned ?? false,
    isArchived: dialog.archived ?? false,
    lastMessageDate: dialog.date ?? null,
    lastMessage: dialog.message?.message?.slice(0, 100) ?? null,
  };
}

function messageText(message: { message?: string }): string {
  if (typeof message.message === "string") {
    return message.message;
  }
  return "";
}

function messageSenderName(message: { sender?: unknown }): string | null {
  if (!message.sender || typeof message.sender !== "object") {
    return null;
  }

  const sender = message.sender as {
    firstName?: string;
    username?: string;
    title?: string;
  };

  return (
    sender.firstName ??
    sender.username ??
    sender.title ??
    null
  );
}

function extractSentIdFromUpdates(result: unknown): number | null {
  if (result instanceof Api.Updates || result instanceof Api.UpdatesCombined) {
    for (const update of result.updates) {
      if (update instanceof Api.UpdateMessageID) {
        return update.id;
      }
    }

    const newMsg = result.updates.find(
      (u): u is Api.UpdateNewMessage => u.className === "UpdateNewMessage"
    );
    const inner = newMsg?.message;
    if (inner && typeof inner === "object" && "id" in inner) {
      return (inner as { id: number }).id;
    }
  }

  return null;
}

function senderIdFromPeer(peer: Api.TypePeer | undefined): string | undefined {
  if (!peer) {
    return undefined;
  }

  if (peer instanceof Api.PeerUser) {
    return peer.userId.toString();
  }

  if (peer instanceof Api.PeerChannel) {
    return peer.channelId.toString();
  }

  if (peer instanceof Api.PeerChat) {
    return peer.chatId.toString();
  }

  return undefined;
}

function userDisplayName(user: Api.User): string {
  if (user.firstName) {
    return `${user.firstName}${user.lastName ? ` ${user.lastName}` : ""}`;
  }

  return user.username ?? `User ${user.id}`;
}

export type GramJsBridgeHandle = {
  bridge: TelegramBridge;
  disconnect: () => Promise<void>;
};

export async function createGramJsBridge(
  env: TelegramMcpEnv
): Promise<GramJsBridgeHandle> {
  const apiId = Number.parseInt(env.TELEGRAM_API_ID, 10);
  if (!Number.isFinite(apiId)) {
    throw new Error("TELEGRAM_API_ID must be a finite integer");
  }

  const session = new StringSession(env.TELEGRAM_SESSION);
  const client = new TelegramClient(session, apiId, env.TELEGRAM_API_HASH, {
    connectionRetries: 5,
  });

  await client.connect();
  const authorized = await client.checkAuthorization();
  if (!authorized) {
    await client.disconnect();
    throw new Error("Telegram session is not authorized");
  }

  const bridge: TelegramBridge = {
    sendMessage: async ({ chatId, text, replyToId }) => {
      const sent = await client.sendMessage(chatId, {
        message: text,
        ...(replyToId !== undefined ? { replyTo: replyToId } : {}),
      });

      return {
        id: sent.id,
        date: sent.date,
      };
    },
    getDialogs: async ({ limit, archived }) => {
      const list = await client.getDialogs({ limit, archived });
      return list.map((d) => dialogRowFromGramJs(d));
    },
    getHistory: async ({ chatId, limit, offsetId }) => {
      const list = await client.getMessages(chatId, {
        limit,
        ...(offsetId !== undefined ? { offsetId } : {}),
      });

      return list.map(
        (m): HistoryMessageRow => ({
          id: m.id,
          text: messageText(m),
          senderId: m.senderId?.toString() ?? null,
          senderName: messageSenderName(m),
          timestamp: m.date,
          isOutgoing: m.out ?? false,
        })
      );
    },
    quoteReply: async ({
      chatId,
      messageId,
      quoteText,
      text,
      quoteOffset = 0,
    }) => {
      const peer = await client.getInputEntity(chatId);
      const replyTo = new Api.InputReplyToMessage({
        replyToMsgId: messageId,
        quoteText,
        quoteOffset,
      });

      const result = await client.invoke(
        new Api.messages.SendMessage({
          peer,
          message: text,
          replyTo,
          randomId: helpers.generateRandomBigInt(),
        })
      );

      return {
        messageId: extractSentIdFromUpdates(result),
        quotedText: quoteText,
        replyText: text,
      };
    },
    getReplies: async ({ chatId, messageId, limit }) => {
      const peer = await client.getInputEntity(chatId);
      const result = await client.invoke(
        new Api.messages.GetReplies({
          peer,
          msgId: messageId,
          offsetId: 0,
          offsetDate: 0,
          addOffset: 0,
          limit,
          maxId: 0,
          minId: 0,
          hash: helpers.returnBigInt(0),
        })
      );

      const userMap = new Map<string, string>();
      if ("users" in result) {
        for (const user of result.users) {
          if (user instanceof Api.User) {
            userMap.set(user.id.toString(), userDisplayName(user));
          }
        }
      }

      const replies: Array<{
        id: number;
        text: string;
        senderId: string;
        senderName?: string;
        date: string;
        replyToId?: number;
      }> = [];

      if ("messages" in result) {
        for (const msg of result.messages) {
          if (msg instanceof Api.Message) {
            const senderId = senderIdFromPeer(msg.fromId) ?? "unknown";
            replies.push({
              id: msg.id,
              text: msg.message ?? "",
              senderId,
              senderName: userMap.get(senderId),
              date: new Date(msg.date * 1000).toISOString(),
              replyToId: msg.replyTo?.replyToMsgId,
            });
          }
        }
      }

      replies.sort(
        (a, b) => new Date(a.date).getTime() - new Date(b.date).getTime()
      );

      const totalCount = "count" in result ? result.count : replies.length;

      let summary = `Found ${replies.length} replies`;
      if (totalCount > replies.length) {
        summary += ` (${totalCount} total)`;
      }

      summary += ` to message #${messageId}:\n\n`;

      for (const msg of replies.slice(0, 10)) {
        const sender = msg.senderName ?? msg.senderId;
        const preview =
          msg.text.length > 100 ? `${msg.text.slice(0, 100)}...` : msg.text;
        summary += `[${sender}]: ${preview}\n`;
      }

      if (replies.length > 10) {
        summary += `\n... and ${replies.length - 10} more replies`;
      }

      return {
        parentMessageId: messageId,
        totalReplies: totalCount,
        fetchedReplies: replies.length,
        replies,
        message: summary,
      };
    },
    editMessage: async ({ chatId, messageId, text }) => {
      const result = await client.editMessage(chatId, {
        message: messageId,
        text,
        parseMode: "md",
      });

      return {
        messageId,
        chatId,
        edited: true,
        date: result?.date ?? Math.floor(Date.now() / 1000),
      };
    },
    scheduleMessage: async ({ chatId, text, scheduleTimestamp }) => {
      const entity = await client.getEntity(chatId);
      const result = await client.invoke(
        new Api.messages.SendMessage({
          peer: entity,
          message: text,
          scheduleDate: scheduleTimestamp,
          randomId: helpers.generateRandomBigInt(),
        })
      );

      return {
        chatId,
        scheduledFor: new Date(scheduleTimestamp * 1000).toISOString(),
        messageId: extractSentIdFromUpdates(result),
      };
    },
    getScheduledMessages: async ({ chatId }) => {
      const entity = await client.getEntity(chatId);
      const result = await client.invoke(
        new Api.messages.GetScheduledHistory({
          peer: entity,
          hash: helpers.returnBigInt(0),
        })
      );

      const raw = ("messages" in result ? result.messages : []) as Api.Message[];
      const messages = raw.map((msg) => ({
        id: msg.id,
        text: msg.message ?? null,
        scheduledFor: msg.date
          ? new Date(msg.date * 1000).toISOString()
          : null,
        hasMedia: Boolean(msg.media),
      }));

      return {
        chatId,
        count: messages.length,
        messages,
      };
    },
    deleteScheduledMessages: async ({ chatId, messageIds }) => {
      const entity = await client.getEntity(chatId);

      try {
        await client.invoke(
          new Api.messages.DeleteScheduledMessages({
            peer: entity,
            id: messageIds,
          })
        );
      } catch (error) {
        if (isMessageIdInvalidError(error)) {
          throw new Error(
            "One or more message IDs are invalid or not scheduled messages."
          );
        }

        throw error;
      }

      return {
        chatId,
        deletedIds: messageIds,
        deletedCount: messageIds.length,
      };
    },
    sendScheduledNow: async ({ chatId, messageIds }) => {
      const entity = await client.getEntity(chatId);

      try {
        await client.invoke(
          new Api.messages.SendScheduledMessages({
            peer: entity,
            id: messageIds,
          })
        );
      } catch (error) {
        if (isMessageIdInvalidError(error)) {
          throw new Error(
            "One or more message IDs are invalid or not scheduled messages."
          );
        }

        throw error;
      }

      return {
        chatId,
        sentIds: messageIds,
        sentCount: messageIds.length,
      };
    },
    searchMessages: async ({ chatId, query, limit }) => {
      const entity = await client.getEntity(chatId);
      const result = await client.invoke(
        new Api.messages.Search({
          peer: entity,
          q: query,
          filter: new Api.InputMessagesFilterEmpty(),
          limit,
        })
      );

      const resultData = result as Api.messages.Messages;
      const messages = resultData.messages.map((msg) => {
        const m = msg as Api.Message;
        return {
          id: m.id,
          text: m.message ?? "",
          senderId: senderIdFromPeer(m.fromId) ?? null,
          date: m.date,
          timestamp: new Date(m.date * 1000).toISOString(),
        };
      });

      return {
        query,
        chatId,
        count: messages.length,
        messages,
      };
    },
    pinMessage: async ({
      chat_id,
      message_id,
      silent = false,
      both_sides = true,
    }) => {
      await client.invoke(
        new Api.messages.UpdatePinnedMessage({
          peer: chat_id,
          id: message_id,
          silent,
          pmOneside: !both_sides,
        })
      );

      return {
        chat_id,
        message_id,
        pinned: true,
        message: `📌 Message #${message_id} pinned`,
      };
    },
    unpinMessage: async ({ chat_id, message_id, unpin_all = false }) => {
      if (unpin_all) {
        await client.invoke(
          new Api.messages.UnpinAllMessages({
            peer: chat_id,
          })
        );

        return {
          chat_id,
          unpinned_all: true as const,
          message: "📌 All messages unpinned",
        };
      }

      await client.invoke(
        new Api.messages.UpdatePinnedMessage({
          peer: chat_id,
          id: message_id ?? 0,
          unpin: true,
        })
      );

      return {
        chat_id,
        message_id,
        unpinned: true as const,
        message: message_id
          ? `📌 Message #${message_id} unpinned`
          : "📌 Latest pinned message unpinned",
      };
    },
    forwardMessages: async ({
      fromChatId,
      toChatId,
      messageIds,
      silent = false,
      background = false,
    }) => {
      await client.invoke(
        new Api.messages.ForwardMessages({
          fromPeer: fromChatId,
          toPeer: toChatId,
          id: messageIds,
          silent,
          background,
          randomId: messageIds.map(() => helpers.generateRandomBigInt()),
        })
      );

      return {
        messageCount: messageIds.length,
        fromChatId,
        toChatId,
      };
    },
    deleteMessages: async ({ chatId, messageIds, revoke = true }) => {
      const isChannel = chatId.startsWith("-100");

      if (isChannel) {
        const channel = await client.getEntity(chatId);
        await client.invoke(
          new Api.channels.DeleteMessages({
            channel,
            id: messageIds,
          })
        );
      } else {
        await client.invoke(
          new Api.messages.DeleteMessages({
            id: messageIds,
            revoke,
          })
        );
      }

      return {
        deletedCount: messageIds.length,
        messageIds,
        revoked: revoke,
      };
    },
    getChatInfo: async ({ chatId }) => gramJsGetChatInfo(client, chatId),
    markAsRead: async (input) => gramJsMarkAsRead(client, input),
    joinChannel: async ({ channel }) => gramJsJoinChannel(client, channel),
    leaveChannel: async ({ channel }) => gramJsLeaveChannel(client, channel),
    createChannel: async (input) => gramJsCreateChannel(client, input),
    editChannelInfo: async (input) => gramJsEditChannelInfo(client, input),
    inviteToChannel: async (input) => gramJsInviteToChannel(client, input),
    getAdminedChannels: async ({ forPersonal }) =>
      gramJsGetAdminedChannels(client, forPersonal),
    checkChannelUsername: async ({ channelId, username }) =>
      gramJsCheckChannelUsername(client, channelId, username),
    setChannelUsername: async ({ channelId, username }) =>
      gramJsSetChannelUsername(client, channelId, username),
    getMe: async () => gramJsGetMe(client),
    getParticipants: async (input) => gramJsGetParticipants(client, input),
    kickUser: async (input) => gramJsKickUser(client, input),
    banUser: async (input) => gramJsBanUser(client, input),
    unbanUser: async (input) => gramJsUnbanUser(client, input),
    createGroup: async (input) => gramJsCreateGroup(client, input),
    setChatPhoto: async (input) => gramJsSetChatPhoto(client, input),
    createPoll: async (input) => gramJsCreatePoll(client, input),
    createQuiz: async (input) => gramJsCreateQuiz(client, input),
    sendReplyKeyboard: async (input) =>
      gramJsSendReplyKeyboard(client, input),
    sendReaction: async (input) => gramJsSendReaction(client, input),
    sendDice: async (input) => gramJsSendDice(client, input),
    sendPhoto: async (input) => gramJsSendPhoto(client, input),
    sendVoice: async (input) => gramJsSendVoice(client, input),
    sendSticker: async (input) => gramJsSendSticker(client, input),
    sendGif: async (input) => gramJsSendGif(client, input),
    downloadMedia: async (input) => gramJsDownloadMedia(client, input),
    visionAnalyze: async (input) => gramJsVisionAnalyze(client, input),
    transcribeAudio: async (input) => gramJsTranscribeAudio(client, input),
    updateProfile: async (input) => gramJsUpdateProfile(client, input),
    setBio: async (input) => gramJsSetBio(client, input),
    setOwnUsername: async (input) => gramJsSetOwnUsername(client, input),
    setPersonalChannel: async (input) =>
      gramJsSetPersonalChannel(client, input),
    getFolders: async () => gramJsGetFolders(client),
    createFolder: async (input) => gramJsCreateFolder(client, input),
    addChatToFolder: async (input) => gramJsAddChatToFolder(client, input),
    blockUser: async (input) => gramJsBlockUser(client, input),
    getBlocked: async (input) => gramJsGetBlocked(client, input),
    getCommonChats: async (input) => gramJsGetCommonChats(client, input),
    getUserInfo: async (input) => gramJsGetUserInfo(client, input),
    resolveUsername: async (input) => gramJsResolveUsername(client, input),
    sendStory: async (input) => gramJsSendStory(client, input),
  };

  return {
    bridge,
    disconnect: () => client.disconnect(),
  };
}
