import { z } from "zod";
import type { TelegramBridge } from "../../bridge.js";

export const setChatPhotoToolShape = {
  chat_id: z
    .string()
    .trim()
    .min(1)
    .describe("Group/channel ID or username"),
  photo_path: z
    .string()
    .trim()
    .min(1)
    .optional()
    .describe("Local path to image file (JPG, PNG)"),
  delete_photo: z
    .boolean()
    .optional()
    .describe("Set true to remove the current chat photo"),
} as const;

export const setChatPhotoInputSchema = z
  .object(setChatPhotoToolShape)
  .refine(
    (data) =>
      data.delete_photo === true ||
      (data.photo_path !== undefined && data.photo_path.length > 0),
    {
      message: "Provide photo_path or delete_photo=true",
    }
  );

export async function handleSetChatPhoto(
  bridge: TelegramBridge,
  input: z.infer<typeof setChatPhotoInputSchema>
): Promise<Awaited<ReturnType<TelegramBridge["setChatPhoto"]>>> {
  const parsed = setChatPhotoInputSchema.parse(input);
  return bridge.setChatPhoto({
    chat_id: parsed.chat_id,
    photo_path: parsed.photo_path,
    delete_photo: parsed.delete_photo,
  });
}
