import { z } from "zod";
import type { TelegramBridge } from "../../bridge.js";

const DICE_EMOTICONS = ["🎲", "🎯", "🏀", "⚽", "🎰", "🎳"] as const;

export const sendDiceToolShape = {
  chat_id: z.string().trim().min(1).describe("Chat ID or username"),
  emoticon: z
    .enum(DICE_EMOTICONS)
    .optional()
    .default("🎲")
    .describe("Dice/game emoji (default 🎲)"),
  reply_to: z.number().int().optional().describe("Message ID to reply to"),
} as const;

export const sendDiceInputSchema = z.object(sendDiceToolShape);

export async function handleSendDice(
  bridge: TelegramBridge,
  input: z.infer<typeof sendDiceInputSchema>
): Promise<Awaited<ReturnType<TelegramBridge["sendDice"]>>> {
  const parsed = sendDiceInputSchema.parse(input);
  return bridge.sendDice(parsed);
}
