import { z } from "zod";
import type { TelegramBridge } from "../../bridge.js";

export const sendPhotoToolShape = {
  chatId: z
    .string()
    .trim()
    .min(1)
    .describe("Numeric chat ID or @username"),
  photoPath: z
    .string()
    .trim()
    .min(1)
    .describe("Local file path to the photo (JPG, PNG, WEBP)"),
  caption: z.string().optional().describe("Optional caption"),
  replyToId: z.number().int().optional().describe("Optional message ID to reply to"),
} as const;

export const sendPhotoInputSchema = z.object(sendPhotoToolShape);

export async function handleSendPhoto(
  bridge: TelegramBridge,
  input: z.infer<typeof sendPhotoInputSchema>
): Promise<Awaited<ReturnType<TelegramBridge["sendPhoto"]>>> {
  const parsed = sendPhotoInputSchema.parse(input);
  return bridge.sendPhoto({
    chatId: parsed.chatId,
    photoPath: parsed.photoPath,
    caption: parsed.caption,
    replyToId: parsed.replyToId,
  });
}
