import { z } from "zod";
import type { TelegramBridge } from "../../bridge.js";

export const checkUsernameToolShape = {
  username: z.string().trim().min(1),
} as const;

export const checkUsernameInputSchema = z.object(checkUsernameToolShape);

export async function handleCheckUsername(
  bridge: TelegramBridge,
  input: z.infer<typeof checkUsernameInputSchema>
): Promise<Awaited<ReturnType<TelegramBridge["resolveUsername"]>>> {
  const parsed = checkUsernameInputSchema.parse(input);
  return bridge.resolveUsername({ username: parsed.username });
}
