import { z } from "zod";
import type { TelegramBridge } from "../../bridge.js";

export const createQuizToolShape = {
  chatId: z.string().trim().min(1).describe("Chat ID for the quiz"),
  question: z.string().min(1).max(300).describe("Quiz question (max 300 characters)"),
  options: z
    .array(z.string().min(1).max(100))
    .min(2)
    .max(10)
    .describe("2–10 options; one is marked correct via correctOptionIndex"),
  correctOptionIndex: z
    .number()
    .int()
    .min(0)
    .describe("Zero-based index of the correct answer"),
  explanation: z
    .string()
    .max(200)
    .optional()
    .describe("Explanation after answering (max 200 characters)"),
  closePeriod: z
    .number()
    .int()
    .min(5)
    .max(600)
    .optional()
    .describe("Auto-close after N seconds (5–600)"),
  closeDate: z
    .number()
    .int()
    .optional()
    .describe("Unix timestamp when quiz closes"),
} as const;

export const createQuizInputSchema = z
  .object(createQuizToolShape)
  .superRefine((data, ctx) => {
    if (data.correctOptionIndex >= data.options.length) {
      ctx.addIssue({
        code: z.ZodIssueCode.custom,
        message: `correctOptionIndex must be at most ${data.options.length - 1}`,
        path: ["correctOptionIndex"],
      });
    }

    if (data.closePeriod !== undefined && data.closeDate !== undefined) {
      ctx.addIssue({
        code: z.ZodIssueCode.custom,
        message: "closePeriod and closeDate are mutually exclusive",
        path: ["closePeriod"],
      });
    }
  });

export async function handleCreateQuiz(
  bridge: TelegramBridge,
  input: z.infer<typeof createQuizInputSchema>
): Promise<Awaited<ReturnType<TelegramBridge["createQuiz"]>>> {
  const parsed = createQuizInputSchema.parse(input);
  return bridge.createQuiz(parsed);
}
