import { z } from "zod";
import type { TelegramBridge } from "../../bridge.js";
import type { JoinChannelResult } from "../../types.js";

export const joinChannelToolShape = {
  channel: z
    .string()
    .trim()
    .min(1)
    .describe(
      "Channel username (with or without @), numeric channel ID, or invite link. Examples: '@mychannel', 'mychannel', '-1001234567890', 'https://t.me/+AbCdEf123'"
    ),
} as const;

export const joinChannelInputSchema = z.object(joinChannelToolShape);

export async function handleJoinChannel(
  bridge: TelegramBridge,
  input: z.infer<typeof joinChannelInputSchema>
): Promise<JoinChannelResult> {
  const parsed = joinChannelInputSchema.parse(input);
  return bridge.joinChannel({ channel: parsed.channel });
}
