import { readFileSync } from "node:fs";
import { Api, helpers } from "telegram";
import type { TelegramClient } from "telegram";
import type {
  BanUserResult,
  CreateGroupResult,
  CreatePollResult,
  CreateQuizResult,
  GetMeResult,
  GetParticipantsResult,
  KickUserResult,
  ParticipantRow,
  ReactResult,
  ReplyKeyboardResult,
  SendDiceResult,
  SetChatPhotoResult,
  UnbanUserResult,
} from "./types.js";

class GramJsUploadBuffer {
  name: string;
  size: number;
  path: string;
  buffer: Buffer;

  constructor(name: string, size: number, path: string, buffer: Buffer) {
    this.name = name;
    this.size = size;
    this.path = path;
    this.buffer = buffer;
  }

  async *[Symbol.asyncIterator]() {
    yield this.buffer;
  }
}

function fullBanRights(untilDate: number): Api.ChatBannedRights {
  return new Api.ChatBannedRights({
    untilDate,
    viewMessages: true,
    sendMessages: true,
    sendMedia: true,
    sendStickers: true,
    sendGifs: true,
    sendGames: true,
    sendInline: true,
    embedLinks: true,
  });
}

function entityClassName(entity: unknown): string | null {
  if (typeof entity !== "object" || entity === null) {
    return null;
  }

  if ("className" in entity && typeof entity.className === "string") {
    return entity.className;
  }

  return null;
}

function isChannelEntity(entity: unknown): boolean {
  const className = entityClassName(entity);
  return className === "Channel" || className === "ChannelForbidden";
}

function isBasicChatEntity(entity: unknown): boolean {
  const className = entityClassName(entity);
  return className === "Chat" || className === "ChatForbidden";
}

function getEntityId(entity: unknown, label: string): bigint {
  if (
    typeof entity === "object" &&
    entity !== null &&
    "id" in entity &&
    typeof entity.id === "bigint"
  ) {
    return entity.id;
  }

  throw new Error(`Could not resolve numeric id for "${label}"`);
}

function requireBanCapableEntity(entity: unknown, toolName: string): void {
  if (!isChannelEntity(entity)) {
    throw new Error(
      `${toolName} only supports supergroups/channels. Basic groups are not supported.`
    );
  }
}

export async function gramJsGetMe(client: TelegramClient): Promise<GetMeResult> {
  const me = (await client.getMe()) as Api.User;
  return {
    id: me.id.toString(),
    username: me.username ?? null,
    firstName: me.firstName ?? null,
    lastName: me.lastName ?? null,
    phone: me.phone ?? null,
    isBot: me.bot ?? false,
    isPremium: me.premium ?? false,
    languageCode: me.langCode ?? null,
    fullName:
      [me.firstName, me.lastName].filter(Boolean).join(" ") || null,
  };
}

export async function gramJsGetParticipants(
  client: TelegramClient,
  input: {
    chatId: string;
    filter?: "all" | "admins" | "banned" | "bots";
    limit?: number;
  }
): Promise<GetParticipantsResult> {
  const { chatId, filter = "all", limit = 100 } = input;
  const entity = await client.getEntity(chatId);

  if (isBasicChatEntity(entity)) {
    if (entityClassName(entity) === "ChatForbidden") {
      throw new Error(
        "Participant listing is not available for this basic group."
      );
    }

    if (filter === "banned") {
      throw new Error(
        "The banned filter is only supported for supergroups/channels."
      );
    }

    const result = (await client.invoke(
      new Api.messages.GetFullChat({
        chatId: helpers.returnBigInt(getEntityId(entity, chatId)),
      })
    )) as Api.messages.ChatFull;

    const fullChat = result.fullChat as Api.ChatFull;
    const participantsContainer = fullChat.participants as Api.ChatParticipants;
    if (
      entityClassName(fullChat) !== "ChatFull" ||
      entityClassName(participantsContainer) !== "ChatParticipants"
    ) {
      throw new Error("Could not read participants for this basic group.");
    }

    const allParticipants: ParticipantRow[] = participantsContainer.participants.map(
      (participant: Api.TypeChatParticipant) => {
        const participantUserId =
          "userId" in participant ? participant.userId : undefined;
        const user = participantUserId
          ? result.users.find((candidate) => candidate.id === participantUserId)
          : undefined;

        return {
          userId: participantUserId?.toString(),
          username:
            user && "username" in user && typeof user.username === "string"
              ? user.username
              : null,
          firstName:
            user && "firstName" in user && typeof user.firstName === "string"
              ? user.firstName
              : null,
          lastName:
            user && "lastName" in user && typeof user.lastName === "string"
              ? user.lastName
              : null,
          isBot: Boolean(user && "bot" in user && user.bot),
          isAdmin:
            participant.className === "ChatParticipantAdmin" ||
            participant.className === "ChatParticipantCreator",
          isBanned: false,
          role:
            participant.className?.replace("ChatParticipant", "").toLowerCase() ||
            "member",
          rank:
            "rank" in participant && typeof participant.rank === "string"
              ? participant.rank
              : null,
        };
      }
    );

    const participants =
      filter === "admins"
        ? allParticipants.filter((participant) => participant.isAdmin)
        : filter === "bots"
          ? allParticipants.filter((participant) => participant.isBot)
          : allParticipants;

    return {
      chatId,
      filter,
      count: participants.length,
      totalCount: allParticipants.length,
      participants,
    };
  }

  if (!isChannelEntity(entity)) {
    throw new Error("This chat type does not support participant listing.");
  }

  let participantFilter: Api.TypeChannelParticipantsFilter;
  switch (filter) {
    case "admins":
      participantFilter = new Api.ChannelParticipantsAdmins();
      break;
    case "banned":
      participantFilter = new Api.ChannelParticipantsBanned({ q: "" });
      break;
    case "bots":
      participantFilter = new Api.ChannelParticipantsBots();
      break;
    case "all":
    default:
      participantFilter = new Api.ChannelParticipantsRecent();
      break;
  }

  const result = await client.invoke(
    new Api.channels.GetParticipants({
      channel: entity,
      filter: participantFilter,
      offset: 0,
      limit,
      hash: helpers.returnBigInt(0),
    })
  );

  const resultData = result as Api.channels.ChannelParticipants;
  const participants: ParticipantRow[] = resultData.participants.map((p) => {
    const participantUserId = "userId" in p ? p.userId : undefined;
    const user = participantUserId
      ? (resultData.users.find(
          (u) => u.id?.toString() === participantUserId?.toString()
        ) as Api.User | undefined)
      : undefined;

    return {
      userId: participantUserId?.toString(),
      username: user?.username ?? null,
      firstName: user?.firstName ?? null,
      lastName: user?.lastName ?? null,
      isBot: user?.bot ?? false,
      isAdmin:
        p.className === "ChannelParticipantAdmin" ||
        p.className === "ChannelParticipantCreator",
      isBanned: p.className === "ChannelParticipantBanned",
      role:
        p.className?.replace("ChannelParticipant", "").toLowerCase() || "member",
      rank: ("rank" in p && p.rank) || null,
    };
  });

  return {
    chatId,
    filter,
    count: participants.length,
    totalCount: resultData.count ?? participants.length,
    participants,
  };
}

export async function gramJsKickUser(
  client: TelegramClient,
  input: { chat_id: string; user_id: string }
): Promise<KickUserResult> {
  const { chat_id, user_id } = input;
  const entity = await client.getEntity(chat_id);

  if (isBasicChatEntity(entity)) {
    if (entityClassName(entity) === "ChatForbidden") {
      throw new Error("You cannot remove users from this basic group.");
    }

    await client.invoke(
      new Api.messages.DeleteChatUser({
        chatId: helpers.returnBigInt(getEntityId(entity, chat_id)),
        userId: await client.getInputEntity(user_id),
      })
    );

    return {
      chat_id,
      user_id,
      kicked: true,
      message: `👢 User ${user_id} removed from basic group`,
    };
  }

  requireBanCapableEntity(entity, "telegram_kick_user");
  const untilDate = Math.floor(Date.now() / 1000) + 60;

  await client.invoke(
    new Api.channels.EditBanned({
      channel: chat_id,
      participant: user_id,
      // Single-request temporary restriction removes the member
      // without relying on a fragile follow-up unban RPC.
      bannedRights: fullBanRights(untilDate),
    })
  );

  return {
    chat_id,
    user_id,
    kicked: true,
    message: `👢 User ${user_id} kicked from chat`,
  };
}

export async function gramJsBanUser(
  client: TelegramClient,
  input: {
    chat_id: string;
    user_id: string;
    delete_messages?: boolean;
    duration_hours?: number;
  }
): Promise<BanUserResult> {
  const {
    chat_id,
    user_id,
    delete_messages = false,
    duration_hours,
  } = input;
  const entity = await client.getEntity(chat_id);
  requireBanCapableEntity(entity, "telegram_ban_user");

  const untilDate = duration_hours
    ? Math.floor(Date.now() / 1000) + duration_hours * 3600
    : 0;

  await client.invoke(
    new Api.channels.EditBanned({
      channel: chat_id,
      participant: user_id,
      bannedRights: fullBanRights(untilDate),
    })
  );

  if (delete_messages) {
    try {
      await client.invoke(
        new Api.channels.DeleteParticipantHistory({
          channel: chat_id,
          participant: user_id,
        })
      );
    } catch {
      /* ignore if not permitted */
    }
  }

  const durationStr = duration_hours ? `for ${duration_hours}h` : "permanently";

  return {
    chat_id,
    user_id,
    banned: true,
    duration_hours: duration_hours ?? null,
    messages_deleted: delete_messages,
    message: `🚫 User ${user_id} banned ${durationStr}`,
  };
}

export async function gramJsUnbanUser(
  client: TelegramClient,
  input: { chat_id: string; user_id: string }
): Promise<UnbanUserResult> {
  const { chat_id, user_id } = input;
  const entity = await client.getEntity(chat_id);
  requireBanCapableEntity(entity, "telegram_unban_user");

  await client.invoke(
    new Api.channels.EditBanned({
      channel: chat_id,
      participant: user_id,
      bannedRights: new Api.ChatBannedRights({ untilDate: 0 }),
    })
  );

  return {
    chat_id,
    user_id,
    unbanned: true,
    message: `✅ User ${user_id} unbanned`,
  };
}

export async function gramJsCreateGroup(
  client: TelegramClient,
  input: { title: string; users: string[] }
): Promise<CreateGroupResult> {
  const { title, users } = input;

  const userEntities: Api.InputUser[] = [];
  const unresolvedUsers: string[] = [];

  for (const user of users) {
    try {
      const entity = await client.getInputEntity(user);
      if (entity instanceof Api.InputPeerUser) {
        userEntities.push(
          new Api.InputUser({
            userId: entity.userId,
            accessHash: entity.accessHash,
          })
        );
        continue;
      }
    } catch {
      unresolvedUsers.push(user);
      continue;
    }

    unresolvedUsers.push(user);
  }

  if (unresolvedUsers.length > 0) {
    throw new Error(
      `Could not resolve all specified users. Unresolved: ${unresolvedUsers.join(", ")}`
    );
  }

  const result = await client.invoke(
    new Api.messages.CreateChat({
      title,
      users: userEntities,
    })
  );

  let chatId: string | undefined;
  let chatTitle: string | undefined;

  const invitedUsers = result as Api.messages.InvitedUsers;
  const updates = invitedUsers.updates;
  if (updates instanceof Api.Updates && updates.chats) {
    for (const chat of updates.chats) {
      if (chat instanceof Api.Chat) {
        chatId = chat.id.toString();
        chatTitle = chat.title;
        break;
      }
    }
  }

  return {
    chat_id: chatId,
    title: chatTitle ?? title,
    members_added: userEntities.length,
    message: `👥 Group "${title}" created with ${userEntities.length} members`,
  };
}

export async function gramJsSetChatPhoto(
  client: TelegramClient,
  input: {
    chat_id: string;
    photo_path?: string;
    delete_photo?: boolean;
  }
): Promise<SetChatPhotoResult> {
  const { chat_id, photo_path, delete_photo = false } = input;

  const entity = await client.getEntity(chat_id);
  const isChannel = isChannelEntity(entity);

  if (delete_photo) {
    if (isChannel) {
      await client.invoke(
        new Api.channels.EditPhoto({
          channel: chat_id,
          photo: new Api.InputChatPhotoEmpty(),
        })
      );
    } else {
      if (!isBasicChatEntity(entity)) {
        throw new Error("This chat type does not support chat photos.");
      }
      await client.invoke(
        new Api.messages.EditChatPhoto({
          chatId: helpers.returnBigInt(getEntityId(entity, chat_id)),
          photo: new Api.InputChatPhotoEmpty(),
        })
      );
    }

    return {
      chat_id,
      photo_deleted: true,
      message: "🖼️ Chat photo deleted",
    };
  }

  if (!photo_path) {
    throw new Error("Must provide either photo_path or delete_photo=true");
  }

  const fileBuffer = readFileSync(photo_path);
  const baseName = photo_path.split(/[/\\]/).pop() ?? "photo.jpg";

  const file = await client.uploadFile({
    file: new GramJsUploadBuffer(
      baseName,
      fileBuffer.length,
      photo_path,
      fileBuffer
    ),
    workers: 1,
  });

  if (isChannel) {
    await client.invoke(
      new Api.channels.EditPhoto({
        channel: chat_id,
        photo: new Api.InputChatUploadedPhoto({ file }),
      })
    );
  } else {
    if (!isBasicChatEntity(entity)) {
      throw new Error("This chat type does not support chat photos.");
    }
    await client.invoke(
      new Api.messages.EditChatPhoto({
        chatId: helpers.returnBigInt(getEntityId(entity, chat_id)),
        photo: new Api.InputChatUploadedPhoto({ file }),
      })
    );
  }

  return {
    chat_id,
    photo_set: true,
    photo_path,
    message: "🖼️ Chat photo updated",
  };
}

export async function gramJsCreatePoll(
  client: TelegramClient,
  input: {
    chatId: string;
    question: string;
    options: string[];
    anonymous?: boolean;
    multipleChoice?: boolean;
    publicVoters?: boolean;
    closePeriod?: number;
    closeDate?: number;
  }
): Promise<CreatePollResult> {
  const {
    chatId,
    question,
    options,
    anonymous = true,
    multipleChoice = false,
    publicVoters = false,
    closePeriod,
    closeDate,
  } = input;

  if (options.length < 2 || options.length > 10) {
    throw new Error("Poll must have between 2 and 10 options");
  }

  const poll = new Api.Poll({
    id: helpers.generateRandomBigInt(),
    question: new Api.TextWithEntities({ text: question, entities: [] }),
    answers: options.map(
      (opt, idx) =>
        new Api.PollAnswer({
          text: new Api.TextWithEntities({ text: opt, entities: [] }),
          option: Buffer.from([idx]),
        })
    ),
    publicVoters: !anonymous && publicVoters,
    multipleChoice,
    closePeriod,
    closeDate,
  });

  await client.invoke(
    new Api.messages.SendMedia({
      peer: chatId,
      media: new Api.InputMediaPoll({ poll }),
      message: "",
      randomId: helpers.generateRandomBigInt(),
    })
  );

  return {
    pollId: poll.id.toString(),
    question,
    optionCount: options.length,
  };
}

export async function gramJsCreateQuiz(
  client: TelegramClient,
  input: {
    chatId: string;
    question: string;
    options: string[];
    correctOptionIndex: number;
    explanation?: string;
    closePeriod?: number;
    closeDate?: number;
  }
): Promise<CreateQuizResult> {
  const {
    chatId,
    question,
    options,
    correctOptionIndex,
    explanation,
    closePeriod,
    closeDate,
  } = input;

  if (options.length < 2 || options.length > 10) {
    throw new Error("Quiz must have between 2 and 10 options");
  }

  if (correctOptionIndex < 0 || correctOptionIndex >= options.length) {
    throw new Error(
      `correctOptionIndex must be between 0 and ${options.length - 1}`
    );
  }

  const poll = new Api.Poll({
    id: helpers.generateRandomBigInt(),
    question: new Api.TextWithEntities({ text: question, entities: [] }),
    answers: options.map(
      (opt, idx) =>
        new Api.PollAnswer({
          text: new Api.TextWithEntities({ text: opt, entities: [] }),
          option: Buffer.from([idx]),
        })
    ),
    quiz: true,
    publicVoters: false,
    multipleChoice: false,
    closePeriod,
    closeDate,
  });

  await client.invoke(
    new Api.messages.SendMedia({
      peer: chatId,
      media: new Api.InputMediaPoll({
        poll,
        correctAnswers: [Buffer.from([correctOptionIndex])],
        solution: explanation,
        solutionEntities: [],
      }),
      message: "",
      randomId: helpers.generateRandomBigInt(),
    })
  );

  return {
    pollId: poll.id.toString(),
    question,
    optionCount: options.length,
    correctOption: options[correctOptionIndex] ?? "",
  };
}

export async function gramJsSendReplyKeyboard(
  client: TelegramClient,
  input: {
    chatId: string;
    text: string;
    buttons: string[][];
    oneTime?: boolean;
    resize?: boolean;
    selective?: boolean;
    replyToId?: number;
  }
): Promise<ReplyKeyboardResult> {
  const {
    chatId,
    text,
    buttons,
    oneTime = false,
    resize = true,
    selective = false,
    replyToId,
  } = input;

  if (buttons.length === 0 || buttons.some((row) => row.length === 0)) {
    throw new Error("Buttons array cannot be empty");
  }

  const keyboard = new Api.ReplyKeyboardMarkup({
    rows: buttons.map(
      (row) =>
        new Api.KeyboardButtonRow({
          buttons: row.map(
            (label) => new Api.KeyboardButton({ text: label })
          ),
        })
    ),
    resize,
    singleUse: oneTime,
    selective,
  });

  const sent = await client.sendMessage(chatId, {
    message: text,
    ...(replyToId !== undefined ? { replyTo: replyToId } : {}),
    buttons: keyboard,
  });

  return {
    messageId: sent.id,
    buttonCount: buttons.reduce((sum, row) => sum + row.length, 0),
    rowCount: buttons.length,
  };
}

export async function gramJsSendReaction(
  client: TelegramClient,
  input: { chatId: string; messageId: number; emoji: string }
): Promise<ReactResult> {
  const { chatId, messageId, emoji } = input;
  const peer = await client.getInputEntity(chatId);

  await client.invoke(
    new Api.messages.SendReaction({
      peer,
      msgId: messageId,
      reaction: [new Api.ReactionEmoji({ emoticon: emoji })],
    })
  );

  return { chatId, messageId, emoji };
}

export async function gramJsSendDice(
  client: TelegramClient,
  input: {
    chat_id: string;
    emoticon?: "🎲" | "🎯" | "🏀" | "⚽" | "🎰" | "🎳";
    reply_to?: number;
  }
): Promise<SendDiceResult> {
  const { chat_id, emoticon = "🎲", reply_to } = input;

  const result = await client.invoke(
    new Api.messages.SendMedia({
      peer: chat_id,
      media: new Api.InputMediaDice({ emoticon }),
      message: "",
      randomId: helpers.generateRandomBigInt(),
      replyTo: reply_to
        ? new Api.InputReplyToMessage({ replyToMsgId: reply_to })
        : undefined,
    })
  );

  let value: number | undefined;
  let messageId: number | undefined;

  if (result instanceof Api.Updates || result instanceof Api.UpdatesCombined) {
    for (const update of result.updates) {
      if (
        update instanceof Api.UpdateNewMessage ||
        update instanceof Api.UpdateNewChannelMessage
      ) {
        const msg = update.message;
        if (msg instanceof Api.Message && msg.media instanceof Api.MessageMediaDice) {
          value = msg.media.value;
          messageId = msg.id;
          break;
        }
      }
    }
  }

  let interpretation = "";
  if (value !== undefined) {
    switch (emoticon) {
      case "🎲":
        interpretation = `Rolled ${value}`;
        break;
      case "🎯":
        interpretation = value === 6 ? "🎯 Bullseye!" : `Scored ${value}/6`;
        break;
      case "🏀":
        interpretation = value >= 4 ? "🏀 Score!" : `Missed (${value}/5)`;
        break;
      case "⚽":
        interpretation = value >= 4 ? "⚽ Goal!" : `Missed (${value}/5)`;
        break;
      case "🎰":
        interpretation =
          value === 64 ? "🎰 JACKPOT 777!" : `Spin result: ${value}/64`;
        break;
      case "🎳":
        interpretation = value === 6 ? "🎳 Strike!" : `Knocked ${value}/6 pins`;
        break;
      default:
        interpretation = "";
    }
  }

  return {
    chat_id,
    emoticon,
    value,
    interpretation,
    message_id: messageId,
    message: `${emoticon} ${interpretation}`,
  };
}
