import { z } from "zod";
import type { TelegramBridge } from "../../bridge.js";
import type { SendScheduledNowResult } from "../../types.js";

export const sendScheduledNowToolShape = {
  chatId: z
    .string()
    .trim()
    .min(1)
    .describe("The chat ID where the scheduled messages are"),
  messageIds: z
    .array(z.number().int())
    .min(1)
    .max(30)
    .describe("Array of scheduled message IDs to send immediately"),
} as const;

export const sendScheduledNowInputSchema = z.object(sendScheduledNowToolShape);

export async function handleSendScheduledNow(
  bridge: TelegramBridge,
  input: z.infer<typeof sendScheduledNowInputSchema>
): Promise<SendScheduledNowResult> {
  const parsed = sendScheduledNowInputSchema.parse(input);
  return bridge.sendScheduledNow({
    chatId: parsed.chatId,
    messageIds: parsed.messageIds,
  });
}
