import { z } from "zod";
import type { TelegramBridge } from "../../bridge.js";

export const setPersonalChannelToolShape = {
  channelId: z
    .string()
    .trim()
    .min(1)
    .optional()
    .describe("Channel ID or @username; omit to remove personal channel"),
} as const;

export const setPersonalChannelInputSchema = z.object(
  setPersonalChannelToolShape
);

export async function handleSetPersonalChannel(
  bridge: TelegramBridge,
  input: z.infer<typeof setPersonalChannelInputSchema>
): Promise<Awaited<ReturnType<TelegramBridge["setPersonalChannel"]>>> {
  const parsed = setPersonalChannelInputSchema.parse(input);
  try {
    return await bridge.setPersonalChannel({
      channelId: parsed.channelId,
    });
  } catch (e) {
    const code =
      typeof e === "object" &&
      e !== null &&
      "errorMessage" in e &&
      typeof (e as { errorMessage: string }).errorMessage === "string"
        ? (e as { errorMessage: string }).errorMessage
        : "";
    if (code === "CHANNEL_INVALID") {
      throw new Error(
        "Invalid channel — ensure you admin this public channel."
      );
    }
    if (code === "CHANNELS_ADMIN_PUBLIC_TOO_MUCH") {
      throw new Error(
        "You administer too many public channels to set a personal channel."
      );
    }
    throw e;
  }
}
