import { z } from "zod";
import type { TelegramBridge } from "../../bridge.js";

export const createGroupToolShape = {
  title: z.string().trim().min(1).describe("Name/title of the group"),
  users: z
    .array(z.string().trim().min(1))
    .min(1)
    .describe("User IDs or usernames to add to the group"),
} as const;

export const createGroupInputSchema = z.object(createGroupToolShape);

export async function handleCreateGroup(
  bridge: TelegramBridge,
  input: z.infer<typeof createGroupInputSchema>
): Promise<Awaited<ReturnType<TelegramBridge["createGroup"]>>> {
  const parsed = createGroupInputSchema.parse(input);
  return bridge.createGroup(parsed);
}
