import { z } from "zod";
import type { TelegramBridge } from "../../bridge.js";
import type { ScheduleMessageResult } from "../../types.js";

export function parseScheduleTimestamp(scheduleDate: string): number | null {
  const trimmed = scheduleDate.trim();

  if (/^\d+$/.test(trimmed)) {
    const unix = Number.parseInt(trimmed, 10);
    return Number.isFinite(unix) ? unix : null;
  }

  const parsedDate = new Date(trimmed);
  if (!Number.isNaN(parsedDate.getTime())) {
    return Math.floor(parsedDate.getTime() / 1000);
  }

  const unix = Number.parseInt(trimmed, 10);
  if (!Number.isFinite(unix)) {
    return null;
  }

  return unix;
}

export const scheduleMessageToolShape = {
  chatId: z
    .string()
    .trim()
    .min(1)
    .describe("The chat ID to send the scheduled message to"),
  text: z
    .string()
    .min(1)
    .max(4096)
    .describe("The message text to send (max 4096 characters)"),
  scheduleDate: z
    .string()
    .min(1)
    .describe(
      "When to send the message (ISO 8601 or Unix timestamp as string)"
    ),
} as const;

export const scheduleMessageInputSchema = z
  .object(scheduleMessageToolShape)
  .superRefine((data, ctx) => {
    const scheduleTimestamp = parseScheduleTimestamp(data.scheduleDate);
    if (scheduleTimestamp === null) {
      ctx.addIssue({
        code: z.ZodIssueCode.custom,
        message:
          "Invalid scheduleDate format. Use ISO 8601 (e.g. '2024-12-25T10:00:00Z') or Unix timestamp.",
      });
      return;
    }

    const now = Math.floor(Date.now() / 1000);
    if (scheduleTimestamp <= now) {
      ctx.addIssue({
        code: z.ZodIssueCode.custom,
        message: "Schedule date must be in the future",
      });
    }
  });

export async function handleScheduleMessage(
  bridge: TelegramBridge,
  input: z.infer<typeof scheduleMessageInputSchema>
): Promise<ScheduleMessageResult> {
  const parsed = scheduleMessageInputSchema.parse(input);
  const scheduleTimestamp = parseScheduleTimestamp(parsed.scheduleDate);
  if (scheduleTimestamp === null) {
    throw new Error("Invalid scheduleDate");
  }

  return bridge.scheduleMessage({
    chatId: parsed.chatId,
    text: parsed.text,
    scheduleTimestamp,
  });
}
