import { z } from "zod";
import type { TelegramBridge } from "../../bridge.js";
import type { SearchMessagesResult } from "../../types.js";

export const searchMessagesToolShape = {
  chatId: z
    .string()
    .trim()
    .min(1)
    .describe(
      "Numeric chat ID (e.g. '123456789') or @username. Never use display names."
    ),
  query: z.string().min(1).describe("The search query text to find in messages"),
  limit: z
    .number()
    .int()
    .min(1)
    .optional()
    .transform((value) => Math.min(value ?? 50, 100))
    .describe(
      "Maximum number of results to return (default: 50, max: 100)"
    ),
} as const;

export const searchMessagesInputSchema = z
  .object(searchMessagesToolShape)
  .superRefine((data, ctx) => {
    const isNumeric = /^-?\d+$/.test(data.chatId);
    const isUsername = data.chatId.startsWith("@");
    if (!isNumeric && !isUsername) {
      ctx.addIssue({
        code: z.ZodIssueCode.custom,
        message: `"${data.chatId}" looks like a display name. Use a numeric chat ID or @username. Call telegram_get_dialogs to find chat IDs.`,
      });
    }
  });

export async function handleSearchMessages(
  bridge: TelegramBridge,
  input: z.infer<typeof searchMessagesInputSchema>
): Promise<SearchMessagesResult> {
  const parsed = searchMessagesInputSchema.parse(input);

  return bridge.searchMessages({
    chatId: parsed.chatId,
    query: parsed.query,
    limit: parsed.limit,
  });
}
