import { z } from "zod";
import type { TelegramBridge } from "../../bridge.js";

export const getMeInputSchema = z.object({});

export const getMeToolShape = getMeInputSchema.shape;

export async function handleGetMe(
  bridge: TelegramBridge,
  input: z.infer<typeof getMeInputSchema>
): Promise<Awaited<ReturnType<TelegramBridge["getMe"]>>> {
  getMeInputSchema.parse(input);
  return bridge.getMe();
}
