import { z } from "zod";
import type { TelegramBridge } from "../../bridge.js";
import type { GetRepliesResult } from "../../types.js";

export const getRepliesToolShape = {
  chatId: z
    .string()
    .trim()
    .min(1)
    .describe("The chat ID where the message is located"),
  messageId: z
    .number()
    .int()
    .describe("The message ID to get replies for (the parent message)"),
  limit: z
    .number()
    .int()
    .min(1)
    .optional()
    .transform((value) => Math.min(value ?? 50, 100))
    .describe(
      "Maximum number of replies to fetch (default: 50, max: 100)"
    ),
} as const;

export const getRepliesInputSchema = z.object(getRepliesToolShape);

export async function handleGetReplies(
  bridge: TelegramBridge,
  input: z.infer<typeof getRepliesInputSchema>
): Promise<GetRepliesResult> {
  const parsed = getRepliesInputSchema.parse(input);

  return bridge.getReplies({
    chatId: parsed.chatId,
    messageId: parsed.messageId,
    limit: parsed.limit,
  });
}
