import { z } from "zod";
import type { TelegramBridge } from "../../bridge.js";

export const blockUserToolShape = {
  userId: z.string().trim().min(1),
} as const;

export const blockUserInputSchema = z.object(blockUserToolShape);

export async function handleBlockUser(
  bridge: TelegramBridge,
  input: z.infer<typeof blockUserInputSchema>
): Promise<Awaited<ReturnType<TelegramBridge["blockUser"]>>> {
  const parsed = blockUserInputSchema.parse(input);
  return bridge.blockUser({ userId: parsed.userId });
}
