import { z } from "zod";
import type { TelegramBridge } from "../../bridge.js";
import type { CreateChannelResult } from "../../types.js";

export const createChannelToolShape = {
  title: z
    .string()
    .min(1)
    .max(128)
    .describe("Name of the channel/megagroup (max 128 characters)"),
  about: z
    .string()
    .max(255)
    .optional()
    .default("")
    .describe(
      "Description of the channel/megagroup (max 255 characters). Visible in info."
    ),
  megagroup: z
    .boolean()
    .optional()
    .default(false)
    .describe(
      "Create as megagroup (large group with chat) instead of broadcast channel. Default: false (broadcast channel)."
    ),
  username: z
    .string()
    .max(32)
    .optional()
    .describe(
      "Public username (5-32 chars, letters/numbers/underscores, no @). If unavailable, the channel is still created without it."
    ),
} as const;

export const createChannelInputSchema = z.object(createChannelToolShape);

export async function handleCreateChannel(
  bridge: TelegramBridge,
  input: z.infer<typeof createChannelInputSchema>
): Promise<CreateChannelResult> {
  const parsed = createChannelInputSchema.parse(input);
  return bridge.createChannel({
    title: parsed.title,
    about: parsed.about,
    megagroup: parsed.megagroup,
    username: parsed.username,
  });
}
