import { z } from "zod";
import type { TelegramBridge } from "../../bridge.js";
import type { SetChannelUsernameResult } from "../../types.js";
import {
  CHANNEL_PUBLIC_USERNAME_REGEX,
  invalidPublicUsernameMessage,
} from "./channel-username.js";

export const setChannelUsernameToolShape = {
  channelId: z.string().trim().min(1).describe("Channel or group ID to update"),
  username: z
    .string()
    .max(32)
    .describe(
      "New username (5-32 chars, no @). Empty string '' removes the public username."
    ),
} as const;

export const setChannelUsernameInputSchema = z
  .object(setChannelUsernameToolShape)
  .superRefine((val, ctx) => {
    const clean = val.username.replace(/^@/, "");
    if (clean.length > 0 && !CHANNEL_PUBLIC_USERNAME_REGEX.test(clean)) {
      ctx.addIssue({
        code: z.ZodIssueCode.custom,
        message: invalidPublicUsernameMessage(),
      });
    }
  });

export async function handleSetChannelUsername(
  bridge: TelegramBridge,
  input: z.infer<typeof setChannelUsernameInputSchema>
): Promise<SetChannelUsernameResult> {
  const parsed = setChannelUsernameInputSchema.parse(input);
  return bridge.setChannelUsername({
    channelId: parsed.channelId,
    username: parsed.username,
  });
}
