export function isVisionAnalyzeEnabled(
  env: NodeJS.ProcessEnv | Record<string, string | undefined> = process.env
): boolean {
  return Boolean(env.OPENAI_API_KEY);
}

export function getRegisteredTelegramToolNames(
  env: NodeJS.ProcessEnv | Record<string, string | undefined> = process.env
): TelegramToolName[] {
  if (isVisionAnalyzeEnabled(env)) {
    return [...TELEGRAM_TOOL_NAMES];
  }

  return TELEGRAM_TOOL_NAMES.filter((name) => name !== "vision_analyze");
}

export function getTelegramToolRegistry(
  env: NodeJS.ProcessEnv | Record<string, string | undefined> = process.env
) {
  if (isVisionAnalyzeEnabled(env)) {
    return toolDefinitions;
  }

  return toolDefinitions.filter((def) => def.name !== "vision_analyze");
}

export const telegramToolRegistry = getTelegramToolRegistry();

function toolJsonPayload(value: unknown): string {
  return JSON.stringify(value, null, 2);
}

export function registerTelegramTools(
  server: McpServer,
  bridge: TelegramBridge
): void {
  for (const def of getTelegramToolRegistry()) {
    server.registerTool(
      def.name,
      {
        description: def.description,
        inputSchema: def.shape,
        _meta: { jsonSchema: def.jsonSchema },
      },
      async (args: unknown) => {
        const run = def.handle as (
          b: TelegramBridge,
          a: unknown
        ) => Promise<unknown>;
        return {
          content: [
            {
              type: "text" as const,
              text: toolJsonPayload(await run(bridge, args)),
            },
          ],
        };
      }
    );
  }
}
