import { z } from "zod";
import type { TelegramBridge } from "../../bridge.js";
import type { DeleteMessagesResult } from "../../types.js";

export const deleteMessageToolShape = {
  chatId: z
    .string()
    .trim()
    .min(1)
    .describe("The chat ID where the messages are located"),
  messageIds: z
    .array(z.number().int())
    .min(1)
    .describe("Array of message IDs to delete. Can delete multiple at once."),
  revoke: z
    .boolean()
    .optional()
    .describe(
      "If true, delete for everyone (both sides). If false, delete only for yourself. Default: true"
    ),
} as const;

export const deleteMessageInputSchema = z.object(deleteMessageToolShape);

export async function handleDeleteMessage(
  bridge: TelegramBridge,
  input: z.infer<typeof deleteMessageInputSchema>
): Promise<DeleteMessagesResult> {
  const parsed = deleteMessageInputSchema.parse(input);
  return bridge.deleteMessages({
    chatId: parsed.chatId,
    messageIds: parsed.messageIds,
    revoke: parsed.revoke,
  });
}
