import { z } from "zod";
import type { TelegramBridge } from "../../bridge.js";

export const getCommonChatsToolShape = {
  userId: z.string().trim().min(1),
  limit: z.number().int().min(1).max(100).optional(),
} as const;

export const getCommonChatsInputSchema = z.object(getCommonChatsToolShape);

export async function handleGetCommonChats(
  bridge: TelegramBridge,
  input: z.infer<typeof getCommonChatsInputSchema>
): Promise<Awaited<ReturnType<TelegramBridge["getCommonChats"]>>> {
  const parsed = getCommonChatsInputSchema.parse(input);
  return bridge.getCommonChats({
    userId: parsed.userId,
    limit: parsed.limit ?? 50,
  });
}
