import { z } from "zod";
import type { TelegramBridge } from "../../bridge.js";

export const setUsernameToolShape = {
  username: z
    .string()
    .max(32)
    .describe("5–32 chars, letters/numbers/underscores, or empty to remove"),
} as const;

export const setUsernameInputSchema = z.object(setUsernameToolShape);

export async function handleSetUsername(
  bridge: TelegramBridge,
  input: z.infer<typeof setUsernameInputSchema>
): Promise<Awaited<ReturnType<TelegramBridge["setOwnUsername"]>>> {
  const parsed = setUsernameInputSchema.parse(input);
  const { username } = parsed;
  if (username.length > 0) {
    if (username.length < 5) {
      throw new Error(
        "Username must be at least 5 characters (or empty to remove)"
      );
    }
    if (!/^[a-zA-Z0-9_]+$/.test(username)) {
      throw new Error(
        "Username can only contain letters, numbers, and underscores"
      );
    }
  }
  try {
    return await bridge.setOwnUsername({ username });
  } catch (e) {
    const msg = e instanceof Error ? e.message : String(e);
    if (msg.includes("USERNAME_OCCUPIED")) {
      throw new Error("Username is already taken. Please choose another.");
    }
    throw e;
  }
}
