import { z } from "zod";
import type { TelegramBridge } from "../../bridge.js";
import type { CheckChannelUsernameResult } from "../../types.js";
import {
  CHANNEL_PUBLIC_USERNAME_REGEX,
  invalidPublicUsernameMessage,
} from "./channel-username.js";

export const checkChannelUsernameToolShape = {
  channelId: z.string().trim().min(1).describe("Channel or group ID"),
  username: z
    .string()
    .min(1)
    .describe(
      "Username to check (5-32 chars, letters/numbers/underscores). Example: 'my_channel'"
    ),
} as const;

export const checkChannelUsernameInputSchema = z
  .object(checkChannelUsernameToolShape)
  .superRefine((val, ctx) => {
    const clean = val.username.replace(/^@/, "");
    if (!CHANNEL_PUBLIC_USERNAME_REGEX.test(clean)) {
      ctx.addIssue({
        code: z.ZodIssueCode.custom,
        message: invalidPublicUsernameMessage(),
      });
    }
  });

export async function handleCheckChannelUsername(
  bridge: TelegramBridge,
  input: z.infer<typeof checkChannelUsernameInputSchema>
): Promise<CheckChannelUsernameResult> {
  const parsed = checkChannelUsernameInputSchema.parse(input);
  return bridge.checkChannelUsername({
    channelId: parsed.channelId,
    username: parsed.username,
  });
}
