import { z } from "zod";
import type { TelegramBridge } from "../../bridge.js";

export const sendMessageToolShape = {
  chatId: z
    .string()
    .trim()
    .min(1)
    .describe("Numeric chat ID (e.g. '123456789') or @username."),
  text: z
    .string()
    .min(1)
    .max(4096)
    .describe("The message text to send (max 4096 characters)"),
  replyToId: z.number().int().optional().describe("Optional message ID to reply to"),
} as const;

export const sendMessageInputSchema = z.object(sendMessageToolShape);

export async function handleSendMessage(
  bridge: TelegramBridge,
  input: z.infer<typeof sendMessageInputSchema>
): Promise<{ messageId: number; date: number }> {
  const parsed = sendMessageInputSchema.parse(input);

  const message = await bridge.sendMessage({
    chatId: parsed.chatId,
    text: parsed.text,
    replyToId: parsed.replyToId,
  });

  return {
    messageId: message.id,
    date: message.date,
  };
}
