import { z } from "zod";
import type { TelegramBridge } from "../../bridge.js";
import type { InviteToChannelResult } from "../../types.js";

export const inviteToChannelToolShape = {
  channelId: z
    .string()
    .trim()
    .min(1)
    .describe("Channel or group ID to invite users to"),
  userIds: z
    .array(z.string().min(1))
    .optional()
    .default([])
    .describe("List of user IDs to invite"),
  usernames: z
    .array(z.string().min(1))
    .optional()
    .default([])
    .describe("List of usernames to invite (with or without @)"),
} as const;

export const inviteToChannelInputSchema = z
  .object(inviteToChannelToolShape)
  .refine((v) => v.userIds.length > 0 || v.usernames.length > 0, {
    message: "Must provide at least one userId or username to invite",
  });

export async function handleInviteToChannel(
  bridge: TelegramBridge,
  input: z.infer<typeof inviteToChannelInputSchema>
): Promise<InviteToChannelResult> {
  const parsed = inviteToChannelInputSchema.parse(input);
  return bridge.inviteToChannel({
    channelId: parsed.channelId,
    userIds: parsed.userIds,
    usernames: parsed.usernames,
  });
}
