import { z } from "zod";
import type { TelegramBridge } from "../../bridge.js";
import type { DeleteScheduledMessagesResult } from "../../types.js";

export const deleteScheduledMessageToolShape = {
  chatId: z
    .string()
    .trim()
    .min(1)
    .describe("The chat ID where the scheduled messages are"),
  messageIds: z
    .array(z.number().int())
    .min(1)
    .max(30)
    .describe("Array of scheduled message IDs to cancel"),
} as const;

export const deleteScheduledMessageInputSchema = z.object(
  deleteScheduledMessageToolShape
);

export async function handleDeleteScheduledMessage(
  bridge: TelegramBridge,
  input: z.infer<typeof deleteScheduledMessageInputSchema>
): Promise<DeleteScheduledMessagesResult> {
  const parsed = deleteScheduledMessageInputSchema.parse(input);
  return bridge.deleteScheduledMessages({
    chatId: parsed.chatId,
    messageIds: parsed.messageIds,
  });
}
