import { z } from "zod";
import type { TelegramBridge } from "../../bridge.js";
import type { HistoryMessageRow } from "../../types.js";

export const getHistoryToolShape = {
  chatId: z
    .string()
    .trim()
    .min(1)
    .describe("Numeric chat ID (e.g. '123456789') or @username."),
  limit: z
    .number()
    .int()
    .min(1)
    .max(100)
    .default(50)
    .describe("Maximum number of messages to retrieve (default: 50, max: 100)"),
  offsetId: z
    .number()
    .int()
    .optional()
    .describe("Message ID to start from for pagination."),
} as const;

export const getHistoryInputSchema = z.object(getHistoryToolShape);

export async function handleGetHistory(
  bridge: TelegramBridge,
  input: z.infer<typeof getHistoryInputSchema>
): Promise<{ messages: HistoryMessageRow[]; count: number; chatId: string }> {
  const parsed = getHistoryInputSchema.parse(input);

  const messages = await bridge.getHistory({
    chatId: parsed.chatId,
    limit: parsed.limit,
    offsetId: parsed.offsetId,
  });

  return {
    messages,
    count: messages.length,
    chatId: parsed.chatId,
  };
}
