import { z } from "zod";
import type { TelegramBridge } from "../../bridge.js";

export const quoteReplyToolShape = {
  chatId: z
    .string()
    .trim()
    .min(1)
    .describe("The chat ID where the message is"),
  messageId: z
    .number()
    .int()
    .describe("The message ID to reply to and quote from"),
  quoteText: z
    .string()
    .min(1)
    .describe(
      "The exact text to quote from the original message (must match exactly)"
    ),
  text: z
    .string()
    .min(1)
    .max(4096)
    .describe("Your reply message text"),
  quoteOffset: z
    .number()
    .int()
    .min(0)
    .optional()
    .describe(
      "Character offset where the quote starts in the original message (default: 0)"
    ),
} as const;

export const quoteReplyInputSchema = z.object(quoteReplyToolShape);

export async function handleQuoteReply(
  bridge: TelegramBridge,
  input: z.infer<typeof quoteReplyInputSchema>
): Promise<{
  messageId: number | null;
  quotedText: string;
  replyText: string;
  message: string;
}> {
  const parsed = quoteReplyInputSchema.parse(input);
  const result = await bridge.quoteReply({
    chatId: parsed.chatId,
    messageId: parsed.messageId,
    quoteText: parsed.quoteText,
    text: parsed.text,
    quoteOffset: parsed.quoteOffset,
  });

  const preview =
    parsed.quoteText.length > 50
      ? `${parsed.quoteText.slice(0, 50)}...`
      : parsed.quoteText;

  return {
    messageId: result.messageId,
    quotedText: result.quotedText,
    replyText: result.replyText,
    message: result.message ?? `Replied with quote: "${preview}"`,
  };
}
