import { z } from "zod";
import type { TelegramBridge } from "../../bridge.js";
import type { PinMessageResult } from "../../types.js";

export const pinMessageToolShape = {
  chat_id: z.string().trim().min(1).describe("Chat ID or username"),
  message_id: z.number().int().describe("ID of the message to pin"),
  silent: z
    .boolean()
    .optional()
    .describe("Pin silently without notification (default: false)"),
  both_sides: z
    .boolean()
    .optional()
    .describe("Pin for both sides in private chats (default: true)"),
} as const;

export const pinMessageInputSchema = z.object(pinMessageToolShape);

export async function handlePinMessage(
  bridge: TelegramBridge,
  input: z.infer<typeof pinMessageInputSchema>
): Promise<PinMessageResult> {
  const parsed = pinMessageInputSchema.parse(input);
  const payload: Parameters<TelegramBridge["pinMessage"]>[0] = {
    chat_id: parsed.chat_id,
    message_id: parsed.message_id,
  };
  if (parsed.silent !== undefined) {
    payload.silent = parsed.silent;
  }

  if (parsed.both_sides !== undefined) {
    payload.both_sides = parsed.both_sides;
  }

  return bridge.pinMessage(payload);
}
