#!/usr/bin/env node
import process from "node:process";
import { StdioServerTransport } from "@modelcontextprotocol/sdk/server/stdio.js";
import { parseTelegramMcpEnv } from "./env.js";
import { createGramJsBridge } from "./gramjs-bridge.js";
import { createTelegramMcpServer } from "./server.js";

function writeBootstrapError(message: string): void {
  process.stderr.write(`${message}\n`);
}

async function main(): Promise<void> {
  const env = parseTelegramMcpEnv(process.env);
  const { bridge, disconnect } = await createGramJsBridge(env);
  const server = createTelegramMcpServer(bridge);
  const transport = new StdioServerTransport();

  const shutdown = async () => {
    try {
      await server.close();
    } finally {
      await disconnect();
    }
  };

  process.once("SIGINT", () => {
    void shutdown().finally(() => process.exit(0));
  });
  process.once("SIGTERM", () => {
    void shutdown().finally(() => process.exit(0));
  });

  await server.connect(transport);
}

void main().catch((error) => {
  const message =
    error instanceof Error ? error.message : "Telegram MCP failed to start";
  writeBootstrapError(message);
  process.exit(1);
});
