import { z } from "zod";
import type { TelegramBridge } from "../../bridge.js";

export const reactToolShape = {
  chatId: z.string().trim().min(1).describe("Chat ID containing the message"),
  messageId: z
    .number()
    .int()
    .describe("Message ID to react to (from history or incoming updates)"),
  emoji: z
    .string()
    .trim()
    .min(1)
    .describe("Single emoji reaction, e.g. 👍 ❤️ 🔥"),
} as const;

export const reactInputSchema = z.object(reactToolShape);

export async function handleReact(
  bridge: TelegramBridge,
  input: z.infer<typeof reactInputSchema>
): Promise<Awaited<ReturnType<TelegramBridge["sendReaction"]>>> {
  const parsed = reactInputSchema.parse(input);
  return bridge.sendReaction(parsed);
}
