import { z } from "zod";
import type { TelegramBridge } from "../../bridge.js";
import type { UnpinMessageResult } from "../../types.js";

export const unpinMessageToolShape = {
  chat_id: z.string().trim().min(1).describe("Chat ID or username"),
  message_id: z
    .number()
    .int()
    .optional()
    .describe(
      "ID of the message to unpin. If omitted and unpin_all is false, unpins the most recent pinned message."
    ),
  unpin_all: z
    .boolean()
    .optional()
    .describe("Unpin ALL pinned messages in the chat (default: false)"),
} as const;

export const unpinMessageInputSchema = z.object(unpinMessageToolShape);

export async function handleUnpinMessage(
  bridge: TelegramBridge,
  input: z.infer<typeof unpinMessageInputSchema>
): Promise<UnpinMessageResult> {
  const parsed = unpinMessageInputSchema.parse(input);
  const payload: Parameters<TelegramBridge["unpinMessage"]>[0] = {
    chat_id: parsed.chat_id,
  };
  if (parsed.message_id !== undefined) {
    payload.message_id = parsed.message_id;
  }

  if (parsed.unpin_all !== undefined) {
    payload.unpin_all = parsed.unpin_all;
  }

  return bridge.unpinMessage(payload);
}
