import { z } from "zod";
import type { TelegramBridge } from "../../bridge.js";

const MAX_POLL_QUESTION_LENGTH = 300;

export const createPollToolShape = {
  chatId: z.string().trim().min(1).describe("Chat ID for the poll"),
  question: z
    .string()
    .min(1)
    .max(MAX_POLL_QUESTION_LENGTH)
    .describe(`Poll question (max ${MAX_POLL_QUESTION_LENGTH} characters)`),
  options: z
    .array(z.string().min(1).max(100))
    .min(2)
    .max(10)
    .describe("2–10 answer options, each max 100 characters"),
  anonymous: z
    .boolean()
    .optional()
    .default(true)
    .describe("Anonymous votes (default true)"),
  multipleChoice: z
    .boolean()
    .optional()
    .default(false)
    .describe("Allow multiple answers (default false)"),
  publicVoters: z
    .boolean()
    .optional()
    .default(false)
    .describe("Show who voted for what when anonymous is false"),
  closePeriod: z
    .number()
    .int()
    .min(5)
    .max(600)
    .optional()
    .describe("Auto-close after N seconds (5–600); do not combine with closeDate"),
  closeDate: z
    .number()
    .int()
    .optional()
    .describe("Unix timestamp when poll closes; do not combine with closePeriod"),
} as const;

export const createPollInputSchema = z
  .object(createPollToolShape)
  .superRefine((data, ctx) => {
    if (data.closePeriod !== undefined && data.closeDate !== undefined) {
      ctx.addIssue({
        code: z.ZodIssueCode.custom,
        message: "closePeriod and closeDate are mutually exclusive",
        path: ["closePeriod"],
      });
    }
  });

export async function handleCreatePoll(
  bridge: TelegramBridge,
  input: z.infer<typeof createPollInputSchema>
): Promise<Awaited<ReturnType<TelegramBridge["createPoll"]>>> {
  const parsed = createPollInputSchema.parse(input);
  return bridge.createPoll(parsed);
}
