import { z } from "zod";
import type { TelegramBridge } from "../../bridge.js";

export const downloadMediaToolShape = {
  chatId: z.string().trim().min(1),
  messageId: z.number().int(),
  filename: z.string().trim().min(1).optional(),
} as const;

export const downloadMediaInputSchema = z.object(downloadMediaToolShape);

export async function handleDownloadMedia(
  bridge: TelegramBridge,
  input: z.infer<typeof downloadMediaInputSchema>
): Promise<Awaited<ReturnType<TelegramBridge["downloadMedia"]>>> {
  const parsed = downloadMediaInputSchema.parse(input);
  return bridge.downloadMedia({
    chatId: parsed.chatId,
    messageId: parsed.messageId,
    filename: parsed.filename,
  });
}
