import { z } from "zod";
import type { TelegramBridge } from "../../bridge.js";
import type { GetScheduledMessagesResult } from "../../types.js";

export const getScheduledMessagesToolShape = {
  chatId: z
    .string()
    .trim()
    .min(1)
    .describe("The chat ID to list scheduled messages for"),
} as const;

export const getScheduledMessagesInputSchema = z.object(
  getScheduledMessagesToolShape
);

export async function handleGetScheduledMessages(
  bridge: TelegramBridge,
  input: z.infer<typeof getScheduledMessagesInputSchema>
): Promise<GetScheduledMessagesResult> {
  const parsed = getScheduledMessagesInputSchema.parse(input);
  return bridge.getScheduledMessages({ chatId: parsed.chatId });
}
