import { z } from "zod";
import type { TelegramBridge } from "../../bridge.js";
import type { ForwardMessagesResult } from "../../types.js";

export const forwardMessageToolShape = {
  fromChatId: z
    .string()
    .trim()
    .min(1)
    .describe("The chat ID where the original message(s) are located"),
  toChatId: z
    .string()
    .trim()
    .min(1)
    .describe("The destination chat ID to forward messages to"),
  messageIds: z
    .array(z.number().int())
    .min(1)
    .describe("Array of message IDs to forward (can forward multiple at once)"),
  silent: z
    .boolean()
    .optional()
    .describe(
      "Send message silently (no notification to recipients). Default: false"
    ),
  background: z
    .boolean()
    .optional()
    .describe(
      "Forward in background (don't mark chat as unread for sender). Default: false"
    ),
} as const;

export const forwardMessageInputSchema = z.object(forwardMessageToolShape);

export async function handleForwardMessage(
  bridge: TelegramBridge,
  input: z.infer<typeof forwardMessageInputSchema>
): Promise<ForwardMessagesResult> {
  const parsed = forwardMessageInputSchema.parse(input);
  const payload: Parameters<TelegramBridge["forwardMessages"]>[0] = {
    fromChatId: parsed.fromChatId,
    toChatId: parsed.toChatId,
    messageIds: parsed.messageIds,
  };
  if (parsed.silent !== undefined) {
    payload.silent = parsed.silent;
  }

  if (parsed.background !== undefined) {
    payload.background = parsed.background;
  }

  return bridge.forwardMessages(payload);
}
