import { z } from "zod";
import type { TelegramBridge } from "../../bridge.js";

export const sendStickerToolShape = {
  chatId: z.string().trim().min(1),
  stickerSetShortName: z.string().trim().min(1).optional(),
  stickerIndex: z.number().int().min(0).optional(),
  stickerPath: z.string().trim().min(1).optional(),
  replyToId: z.number().int().optional(),
} as const;

export const sendStickerInputSchema = z
  .object(sendStickerToolShape)
  .refine(
    (d) =>
      (d.stickerSetShortName !== undefined &&
        d.stickerIndex !== undefined) ||
      d.stickerPath !== undefined,
    { message: "Provide stickerSetShortName+stickerIndex or stickerPath" }
  );

export async function handleSendSticker(
  bridge: TelegramBridge,
  input: z.infer<typeof sendStickerInputSchema>
): Promise<Awaited<ReturnType<TelegramBridge["sendSticker"]>>> {
  const parsed = sendStickerInputSchema.parse(input);
  return bridge.sendSticker({
    chatId: parsed.chatId,
    stickerSetShortName: parsed.stickerSetShortName,
    stickerIndex: parsed.stickerIndex,
    stickerPath: parsed.stickerPath,
    replyToId: parsed.replyToId,
  });
}
