import { z } from "zod";
import type { TelegramBridge } from "../../bridge.js";

export const sendStoryToolShape = {
  mediaPath: z
    .string()
    .trim()
    .min(1)
    .describe("Local story media path. Supported: .jpg, .jpeg, .png, .mp4"),
  caption: z.string().max(200).optional(),
  privacy: z.enum(["everyone", "contacts", "close_friends"]).optional(),
  duration: z.number().int().min(1).max(60).optional(),
} as const;

export const sendStoryInputSchema = z
  .object(sendStoryToolShape)
  .refine((data) => /\.(jpe?g|png|mp4)$/i.test(data.mediaPath), {
    message: "Story media must be a .jpg, .jpeg, .png, or .mp4 file",
    path: ["mediaPath"],
  });

export async function handleSendStory(
  bridge: TelegramBridge,
  input: z.infer<typeof sendStoryInputSchema>
): Promise<Awaited<ReturnType<TelegramBridge["sendStory"]>>> {
  const parsed = sendStoryInputSchema.parse(input);
  return bridge.sendStory({
    mediaPath: parsed.mediaPath,
    caption: parsed.caption,
    privacy: parsed.privacy,
    duration: parsed.duration,
  });
}
