import { z } from "zod";
import type { TelegramBridge } from "../../bridge.js";
import type { EditMessageResult } from "../../types.js";

export const editMessageToolShape = {
  chatId: z
    .string()
    .trim()
    .min(1)
    .describe("The chat ID where the message was sent"),
  messageId: z.number().int().describe("The ID of the message to edit"),
  text: z
    .string()
    .min(1)
    .max(4096)
    .describe("The new text content for the message (max 4096 characters)"),
} as const;

export const editMessageInputSchema = z.object(editMessageToolShape);

export async function handleEditMessage(
  bridge: TelegramBridge,
  input: z.infer<typeof editMessageInputSchema>
): Promise<EditMessageResult> {
  const parsed = editMessageInputSchema.parse(input);
  return bridge.editMessage({
    chatId: parsed.chatId,
    messageId: parsed.messageId,
    text: parsed.text,
  });
}
