import { z } from "zod";
import type { TelegramBridge } from "../../bridge.js";

export const getUserInfoToolShape = {
  userId: z.string().trim().min(1).optional(),
  username: z.string().trim().min(1).optional(),
} as const;

export const getUserInfoInputSchema = z
  .object(getUserInfoToolShape)
  .refine((d) => d.userId !== undefined || d.username !== undefined, {
    message: "Provide userId or username",
  });

export async function handleGetUserInfo(
  bridge: TelegramBridge,
  input: z.infer<typeof getUserInfoInputSchema>
): Promise<Awaited<ReturnType<TelegramBridge["getUserInfo"]>>> {
  const parsed = getUserInfoInputSchema.parse(input);
  return bridge.getUserInfo({
    userId: parsed.userId,
    username: parsed.username,
  });
}
