import { z } from "zod";
import type { TelegramBridge } from "../../bridge.js";

export const setBioToolShape = {
  bio: z.string().max(70).describe("Bio text; empty string removes bio"),
} as const;

export const setBioInputSchema = z.object(setBioToolShape);

export async function handleSetBio(
  bridge: TelegramBridge,
  input: z.infer<typeof setBioInputSchema>
): Promise<Awaited<ReturnType<TelegramBridge["setBio"]>>> {
  const parsed = setBioInputSchema.parse(input);
  return bridge.setBio({ bio: parsed.bio });
}
