import { z } from "zod";
import type { TelegramBridge } from "../../bridge.js";

export const addChatToFolderToolShape = {
  folderId: z.number().int(),
  chatId: z.string().trim().min(1),
} as const;

export const addChatToFolderInputSchema = z.object(addChatToFolderToolShape);

export async function handleAddChatToFolder(
  bridge: TelegramBridge,
  input: z.infer<typeof addChatToFolderInputSchema>
): Promise<Awaited<ReturnType<TelegramBridge["addChatToFolder"]>>> {
  const parsed = addChatToFolderInputSchema.parse(input);
  return bridge.addChatToFolder({
    folderId: parsed.folderId,
    chatId: parsed.chatId,
  });
}
